import React, { useState, useRef, useEffect } from 'react';
import { 
  GraduationCap, Play, Pause, ChevronRight, BookOpen, 
  Repeat, Eye, EyeOff, Volume2, ArrowLeft, Star, 
  CheckCircle2, Brain, Sparkles, LayoutGrid, Quote 
} from 'lucide-react';
import { generateQuiz } from '../services/geminiService';
import { QuizQuestion } from '../types';

interface AcademyProps {
  onNavigate: (tab: string) => void;
  language?: string;
}

// --- Types for the Learning Modules ---

interface Verse {
  text: string;
  translation: string;
  audio: string;
  verseNumber: number;
}

interface LessonModule {
  id: string;
  type: 'quran' | 'hadith';
  title: { en: string; fr: string };
  subtitle: { en: string; fr: string };
  description: { en: string; fr: string };
  color: string;
  icon: React.ElementType;
  progress: number;
  content: Verse[]; // For Quran this is verses, for Hadith this is segments
}

// --- Mock Data for Demonstration ---
// Using real audio URLs from AlQuran Cloud for Fatiha
const MOCK_MODULES: LessonModule[] = [
  {
    id: 'fatiha',
    type: 'quran',
    title: { en: 'Surah Al-Fatiha', fr: 'Sourate Al-Fatiha' },
    subtitle: { en: 'The Opening • 7 Verses', fr: 'L\'Ouverture • 7 Versets' },
    description: { en: 'The foundation of the Quran. Essential for every prayer.', fr: 'Le fondement du Coran. Essentiel pour chaque prière.' },
    color: 'from-emerald-500 to-teal-600',
    icon: BookOpen,
    progress: 30,
    content: [
      { verseNumber: 1, text: "بِسْمِ ٱللَّهِ ٱلرَّحْمَـٰنِ ٱلرَّحِيمِ", translation: "In the name of Allah, the Entirely Merciful, the Especially Merciful.", audio: "https://cdn.islamic.network/quran/audio/128/ar.alafasy/1.mp3" },
      { verseNumber: 2, text: "ٱلْحَمْدُ لِلَّهِ رَبِّ ٱلْعَـٰلَمِينَ", translation: "[All] praise is [due] to Allah, Lord of the worlds -", audio: "https://cdn.islamic.network/quran/audio/128/ar.alafasy/2.mp3" },
      { verseNumber: 3, text: "ٱلرَّحْمَـٰنِ ٱلرَّحِيمِ", translation: "The Entirely Merciful, the Especially Merciful,", audio: "https://cdn.islamic.network/quran/audio/128/ar.alafasy/3.mp3" },
      { verseNumber: 4, text: "مَـٰلِكِ يَوْمِ ٱلدِّينِ", translation: "Sovereign of the Day of Recompense.", audio: "https://cdn.islamic.network/quran/audio/128/ar.alafasy/4.mp3" },
      { verseNumber: 5, text: "إِيَّاكَ نَعْبُدُ وَإِيَّاكَ نَسْتَعِينُ", translation: "It is You we worship and You we ask for help.", audio: "https://cdn.islamic.network/quran/audio/128/ar.alafasy/5.mp3" },
      { verseNumber: 6, text: "ٱهْدِنَا ٱلصِّرَٰطَ ٱلْمُسْتَقِيمَ", translation: "Guide us to the straight path -", audio: "https://cdn.islamic.network/quran/audio/128/ar.alafasy/6.mp3" },
      { verseNumber: 7, text: "صِرَٰطَ ٱلَّذِينَ أَنْعَمْتَ عَلَيْهِمْ غَيْرِ ٱلْمَغْضُوبِ عَلَيْهِمْ وَلَا ٱلضَّالِّينَ", translation: "The path of those upon whom You have bestowed favor, not of those who have evoked [Your] anger or of those who are astray.", audio: "https://cdn.islamic.network/quran/audio/128/ar.alafasy/7.mp3" }
    ]
  },
  {
    id: 'hadith_niyyah',
    type: 'hadith',
    title: { en: 'Actions are by Intentions', fr: 'Les actes ne valent que par l\'intention' },
    subtitle: { en: 'Hadith #1 • Sahih Bukhari', fr: 'Hadith #1 • Sahih Bukhari' },
    description: { en: 'Understanding sincerity (Ikhlas) in all our deeds.', fr: 'Comprendre la sincérité (Ikhlas) dans tous nos actes.' },
    color: 'from-indigo-500 to-violet-600',
    icon: Quote,
    progress: 0,
    content: [
      { verseNumber: 1, text: "إِنَّمَا الأَعْمَالُ بِالنِّيَّاتِ", translation: "Verily, actions are but by intentions,", audio: "" },
      { verseNumber: 2, text: "وَإِنَّمَا لِكُلِّ امْرِئٍ مَا نَوَى", translation: "and every person will have only what they intended.", audio: "" },
      { verseNumber: 3, text: "فَمَنْ كَانَتْ هِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ", translation: "So whoever emigrated to Allah and His Messenger,", audio: "" },
      { verseNumber: 4, text: "فَهِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ", translation: "his emigration is to Allah and His Messenger.", audio: "" }
    ]
  },
  {
    id: 'ikhlas',
    type: 'quran',
    title: { en: 'Surah Al-Ikhlas', fr: 'Sourate Al-Ikhlas' },
    subtitle: { en: 'The Sincerity • 4 Verses', fr: 'Le Monothéisme Pur • 4 Versets' },
    description: { en: 'Equivalent to one-third of the Quran.', fr: 'Équivaut à un tiers du Coran.' },
    color: 'from-amber-500 to-orange-600',
    icon: Star,
    progress: 10,
    content: [
      { verseNumber: 1, text: "قُلْ هُوَ ٱللَّهُ أَحَدٌ", translation: "Say, 'He is Allah, [who is] One,", audio: "https://cdn.islamic.network/quran/audio/128/ar.alafasy/6233.mp3" },
      { verseNumber: 2, text: "ٱللَّهُ ٱلصَّمَدُ", translation: "Allah, the Eternal Refuge.", audio: "https://cdn.islamic.network/quran/audio/128/ar.alafasy/6234.mp3" },
      { verseNumber: 3, text: "لَمْ يَلِدْ وَلَمْ يُولَدْ", translation: "He neither begets nor is born,", audio: "https://cdn.islamic.network/quran/audio/128/ar.alafasy/6235.mp3" },
      { verseNumber: 4, text: "وَلَمْ يَكُن لَّهُۥ كُفُوًا أَحَدٌۢ", translation: "Nor is there to Him any equivalent.'", audio: "https://cdn.islamic.network/quran/audio/128/ar.alafasy/6236.mp3" }
    ]
  }
];

const Academy: React.FC<AcademyProps> = ({ onNavigate, language = 'en' }) => {
  const [activeModule, setActiveModule] = useState<LessonModule | null>(null);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [hideText, setHideText] = useState(false); // Hifz mode
  const [isLooping, setIsLooping] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);

  const t = {
    title: language === 'fr' ? 'Académie' : 'Academy',
    subtitle: language === 'fr' ? 'Apprenez, Mémorisez, Grandissez' : 'Learn, Memorize, Grow',
    continue: language === 'fr' ? 'Reprendre' : 'Continue Learning',
    modules: language === 'fr' ? 'Modules d\'apprentissage' : 'Learning Modules',
    hifzMode: language === 'fr' ? 'Mode Hifz (Cacher)' : 'Hifz Mode (Hide)',
    show: language === 'fr' ? 'Voir' : 'Show',
    next: language === 'fr' ? 'Suivant' : 'Next',
    prev: language === 'fr' ? 'Précédent' : 'Prev',
    quiz: language === 'fr' ? 'Quiz IA' : 'AI Quiz'
  };

  // Audio Logic
  useEffect(() => {
    if (activeModule && audioRef.current) {
      if (activeModule.type === 'quran') {
         audioRef.current.src = activeModule.content[currentIndex].audio;
         if (isPlaying) audioRef.current.play();
      }
    }
  }, [currentIndex, activeModule]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;

    const handleEnded = () => {
      if (isLooping) {
        audio.currentTime = 0;
        audio.play();
      } else {
        if (currentIndex < (activeModule?.content.length || 0) - 1) {
          setCurrentIndex(c => c + 1);
        } else {
          setIsPlaying(false);
        }
      }
    };

    audio.addEventListener('ended', handleEnded);
    return () => audio.removeEventListener('ended', handleEnded);
  }, [isLooping, currentIndex, activeModule]);

  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  const handleModuleSelect = (module: LessonModule) => {
    setActiveModule(module);
    setCurrentIndex(0);
    setIsPlaying(false);
    setHideText(false);
  };

  // --- PLAYER VIEW ---
  if (activeModule) {
    const currentItem = activeModule.content[currentIndex];
    const progressPercent = ((currentIndex + 1) / activeModule.content.length) * 100;

    return (
      <div className="h-full flex flex-col bg-slate-900 animate-fade-in relative overflow-hidden">
        <audio ref={audioRef} />

        {/* Background Blur */}
        <div className={`absolute top-0 inset-x-0 h-[60%] bg-gradient-to-b ${activeModule.color} opacity-20 pointer-events-none`}></div>
        <div className="absolute top-0 right-0 w-64 h-64 bg-emerald-500 rounded-full mix-blend-multiply filter blur-3xl opacity-10 animate-pulse-slow"></div>

        {/* Header */}
        <div className="relative z-10 p-6 flex items-center justify-between">
           <button 
             onClick={() => {
                setIsPlaying(false);
                setActiveModule(null);
             }}
             className="w-10 h-10 rounded-full bg-white/10 backdrop-blur-md flex items-center justify-center text-white hover:bg-white/20 transition-colors"
           >
             <ArrowLeft size={20} />
           </button>
           <div className="text-center">
              <h2 className="text-white font-bold text-lg">{activeModule.title[language as 'en'|'fr']}</h2>
              <p className="text-slate-300 text-xs">{currentIndex + 1} / {activeModule.content.length}</p>
           </div>
           <button 
             onClick={() => setHideText(!hideText)}
             className={`w-10 h-10 rounded-full flex items-center justify-center transition-colors ${hideText ? 'bg-emerald-500 text-white' : 'bg-white/10 text-slate-300'}`}
             title={t.hifzMode}
           >
             {hideText ? <EyeOff size={20} /> : <Eye size={20} />}
           </button>
        </div>

        {/* Content Area (Visual) */}
        <div className="flex-1 flex flex-col items-center justify-center p-6 text-center relative z-10">
           {/* Card Container */}
           <div className="w-full max-w-sm bg-white/5 backdrop-blur-lg border border-white/10 rounded-[2rem] p-8 shadow-2xl relative transition-all duration-500">

               {/* Icon Glow */}
               <div className="absolute -top-10 left-1/2 -translate-x-1/2 w-20 h-20 rounded-2xl bg-gradient-to-br from-slate-800 to-slate-900 border border-slate-700 flex items-center justify-center shadow-xl">
                  {React.createElement(activeModule.icon, { size: 32, className: "text-emerald-400" })}
               </div>

               <div className="mt-10 space-y-8">
                   <div className={`transition-all duration-500 ${hideText ? 'blur-md select-none opacity-50' : 'blur-0 opacity-100'}`}>
                       <p className="font-arabic text-4xl text-white leading-[2.5] drop-shadow-lg" dir="rtl">
                           {currentItem.text}
                       </p>
                   </div>

                   <div className={`transition-all duration-500 delay-100 ${hideText ? 'opacity-0 translate-y-4' : 'opacity-100 translate-y-0'}`}>
                       <p className="text-slate-300 text-lg leading-relaxed font-medium">
                           {currentItem.translation}
                       </p>
                   </div>
               </div>
           </div>
        </div>

        {/* Controls */}
        <div className="relative z-10 bg-slate-950/80 backdrop-blur-xl border-t border-white/5 p-6 pb-12 rounded-t-[2.5rem]">
            {/* Progress Bar */}
            <div className="mb-8">
               <div className="h-1.5 w-full bg-slate-800 rounded-full overflow-hidden">
                   <div className="h-full bg-emerald-500 transition-all duration-500 ease-out" style={{ width: `${progressPercent}%` }}></div>
               </div>
            </div>

            <div className="flex items-center justify-between max-w-xs mx-auto">
               <button 
                  onClick={() => setIsLooping(!isLooping)}
                  className={`p-3 rounded-full transition-colors ${isLooping ? 'text-emerald-400 bg-emerald-400/10' : 'text-slate-500 hover:text-slate-300'}`}
               >
                  <Repeat size={20} />
               </button>

               <div className="flex items-center gap-6">
                   <button 
                     onClick={() => setCurrentIndex(c => Math.max(0, c - 1))}
                     disabled={currentIndex === 0}
                     className="p-3 rounded-full text-white disabled:opacity-30 hover:bg-white/10 transition-colors"
                   >
                     <ChevronRight size={28} className="rotate-180" />
                   </button>

                   <button 
                     onClick={togglePlay}
                     className="w-20 h-20 rounded-full bg-gradient-to-tr from-emerald-500 to-teal-400 flex items-center justify-center text-white shadow-lg shadow-emerald-500/30 hover:scale-105 active:scale-95 transition-all"
                   >
                      {isPlaying ? <Pause size={32} fill="currentColor" /> : <Play size={32} fill="currentColor" className="ml-1" />}
                   </button>

                   <button 
                     onClick={() => setCurrentIndex(c => Math.min(activeModule.content.length - 1, c + 1))}
                     disabled={currentIndex === activeModule.content.length - 1}
                     className="p-3 rounded-full text-white disabled:opacity-30 hover:bg-white/10 transition-colors"
                   >
                     <ChevronRight size={28} />
                   </button>
               </div>

               <button className="p-3 rounded-full text-slate-500 hover:text-slate-300">
                  <Volume2 size={20} />
               </button>
            </div>
        </div>
      </div>
    );
  }

  // --- DASHBOARD VIEW ---
  return (
    <div className="h-full flex flex-col bg-slate-50 dark:bg-slate-950 animate-fade-in">
      {/* Hero Section */}
      <header className="p-6 pb-2">
        <div className="flex items-center justify-between mb-4">
           <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-emerald-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-emerald-600/30">
                 <GraduationCap size={24} />
              </div>
              <div>
                 <h1 className="text-2xl font-bold text-slate-800 dark:text-slate-100">{t.title}</h1>
                 <p className="text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wider">{t.subtitle}</p>
              </div>
           </div>

           <button 
             onClick={() => onNavigate('quiz-basics')} // Legacy quiz route
             className="w-10 h-10 rounded-full bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 flex items-center justify-center text-emerald-600 dark:text-emerald-400 shadow-sm"
             title={t.quiz}
           >
              <Brain size={20} />
           </button>
        </div>

        {/* Last Played / Continue Banner */}
        <div className="bg-slate-900 dark:bg-slate-800 rounded-3xl p-6 text-white relative overflow-hidden shadow-xl mt-4">
            <div className="absolute top-0 right-0 w-64 h-64 bg-emerald-500/20 rounded-full blur-3xl -mr-16 -mt-16"></div>
            <div className="relative z-10 flex items-center justify-between">
               <div>
                  <h2 className="text-sm font-bold text-emerald-400 uppercase tracking-wider mb-1">{t.continue}</h2>
                  <p className="text-xl font-bold mb-1">Surah Al-Fatiha</p>
                  <p className="text-slate-400 text-xs">Verse 3 of 7</p>
               </div>
               <button 
                  onClick={() => handleModuleSelect(MOCK_MODULES[0])}
                  className="w-12 h-12 rounded-full bg-white text-slate-900 flex items-center justify-center hover:scale-105 transition-transform"
               >
                  <Play size={20} fill="currentColor" className="ml-0.5" />
               </button>
            </div>
            {/* Progress Bar in Banner */}
            <div className="mt-4 h-1.5 w-full bg-white/10 rounded-full overflow-hidden">
               <div className="h-full bg-emerald-400 w-[42%]"></div>
            </div>
        </div>
      </header>

      {/* Modules List */}
      <div className="flex-1 overflow-y-auto px-6 pb-24 space-y-6">
          <div className="flex items-center gap-2 mt-2">
             <LayoutGrid size={18} className="text-slate-400" />
             <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider">{t.modules}</h3>
          </div>

          <div className="grid gap-4">
              {MOCK_MODULES.map((module) => (
                  <button
                    key={module.id}
                    onClick={() => handleModuleSelect(module)}
                    className="group relative overflow-hidden bg-white dark:bg-slate-900 rounded-[2rem] p-1 border border-slate-100 dark:border-slate-800 shadow-sm hover:shadow-lg hover:-translate-y-1 transition-all duration-300 text-left"
                  >
                      <div className="flex items-stretch">
                          {/* Image/Icon Side */}
                          <div className={`w-24 bg-gradient-to-br ${module.color} rounded-[1.7rem] flex items-center justify-center text-white relative overflow-hidden`}>
                             <div className="absolute inset-0 bg-black/10"></div>
                             {React.createElement(module.icon, { size: 32, className: "relative z-10 drop-shadow-md" })}
                          </div>

                          {/* Content Side */}
                          <div className="flex-1 p-4 pl-5">
                             <div className="flex justify-between items-start">
                                 <div>
                                    <h4 className="font-bold text-lg text-slate-800 dark:text-slate-100 leading-tight">
                                        {module.title[language as 'en'|'fr']}
                                    </h4>
                                    <p className="text-xs font-semibold text-emerald-600 dark:text-emerald-400 mt-1 uppercase tracking-wide">
                                        {module.subtitle[language as 'en'|'fr']}
                                    </p>
                                 </div>
                                 {module.progress >= 100 && <CheckCircle2 size={20} className="text-emerald-500" />}
                             </div>

                             <p className="text-sm text-slate-500 dark:text-slate-400 mt-2 line-clamp-2 leading-relaxed">
                                 {module.description[language as 'en'|'fr']}
                             </p>

                             {module.progress > 0 && module.progress < 100 && (
                                <div className="mt-4 flex items-center gap-2">
                                   <div className="flex-1 h-1.5 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                                       <div className={`h-full bg-gradient-to-r ${module.color}`} style={{ width: `${module.progress}%` }}></div>
                                   </div>
                                   <span className="text-[10px] font-bold text-slate-400">{module.progress}%</span>
                                </div>
                             )}
                          </div>
                      </div>
                  </button>
              ))}

              {/* Legacy Links to other sections */}
              <div className="grid grid-cols-2 gap-3 mt-4">
                 <button 
                   onClick={() => onNavigate('hadith')}
                   className="bg-indigo-50 dark:bg-indigo-900/20 p-4 rounded-2xl border border-indigo-100 dark:border-indigo-800 flex flex-col items-center justify-center gap-2 text-indigo-700 dark:text-indigo-300"
                 >
                    <Quote size={24} />
                    <span className="font-bold text-sm">Hadith Collection</span>
                 </button>
                 <button 
                   onClick={() => onNavigate('stories')}
                   className="bg-amber-50 dark:bg-amber-900/20 p-4 rounded-2xl border border-amber-100 dark:border-amber-800 flex flex-col items-center justify-center gap-2 text-amber-700 dark:text-amber-300"
                 >
                    <Sparkles size={24} />
                    <span className="font-bold text-sm">Prophet Stories</span>
                 </button>
              </div>
          </div>
      </div>
    </div>
  );
};

export default Academy;

import React, { useState, useRef, useEffect } from 'react';
import { 
  GraduationCap, Play, Pause, ChevronRight, BookOpen, 
  Repeat, Eye, EyeOff, Volume2, ArrowLeft, Star, 
  CheckCircle2, Brain, Sparkles, LayoutGrid, Quote,
  Search, Loader2, List
} from 'lucide-react';

interface AcademyProps {
  onNavigate: (tab: string) => void;
  language?: string;
}

// --- Types ---

interface Verse {
  text: string;
  translation: string;
  audio: string;
  verseNumber: number;
  meta?: string;
}

interface LessonModule {
  id: string;
  type: 'quran' | 'hadith';
  title: string;
  subtitle: string;
  description: string;
  color: string;
  icon: React.ElementType;
  progress: number;
  content: Verse[];
}

interface SurahDef {
  number: number;
  name: string;
  englishName: string;
  englishNameTranslation: string;
  numberOfAyahs: number;
}

interface BookDef {
  id: string;
  name: string;
  arabicName: string;
  slugs: { en: string; fr: string; ar: string };
}

interface ChapterDef {
  number: string;
  title: string;
}

// --- Constants ---

const HADITH_BOOKS: BookDef[] = [
  { id: 'bukhari', name: 'Sahih al-Bukhari', arabicName: 'صحيح البخاري', slugs: { en: 'eng-bukhari', fr: 'eng-bukhari', ar: 'ara-bukhari' } },
  { id: 'muslim', name: 'Sahih Muslim', arabicName: 'صحيح مسلم', slugs: { en: 'eng-muslim', fr: 'eng-muslim', ar: 'ara-muslim' } },
  { id: 'nasai', name: 'Sunan an-Nasa\'i', arabicName: 'سنن النسائي', slugs: { en: 'eng-nasai', fr: 'eng-nasai', ar: 'ara-nasai' } },
  { id: 'abudawud', name: 'Sunan Abu Dawud', arabicName: 'سنن أبي داود', slugs: { en: 'eng-abudawud', fr: 'eng-abudawud', ar: 'ara-abudawud' } },
  { id: 'tirmidhi', name: 'Jami\' at-Tirmidhi', arabicName: 'جامع الترمذي', slugs: { en: 'eng-tirmidhi', fr: 'eng-tirmidhi', ar: 'ara-tirmidhi' } },
  { id: 'ibnmajah', name: 'Sunan Ibn Majah', arabicName: 'سنن ابن ماجه', slugs: { en: 'eng-ibnmajah', fr: 'eng-ibnmajah', ar: 'ara-ibnmajah' } },
  { id: 'malik', name: 'Muwatta Malik', arabicName: 'موطأ مالك', slugs: { en: 'eng-malik', fr: 'eng-malik', ar: 'ara-malik' } },
];

const Academy: React.FC<AcademyProps> = ({ onNavigate, language = 'en' }) => {
  // View State
  const [activeTab, setActiveTab] = useState<'quran' | 'hadith'>('quran');
  const [view, setView] = useState<'dashboard' | 'chapters' | 'player'>('dashboard');

  // Data State
  const [surahs, setSurahs] = useState<SurahDef[]>([]);
  const [activeBook, setActiveBook] = useState<BookDef | null>(null);
  const [chapters, setChapters] = useState<ChapterDef[]>([]);

  // Player State
  const [activeModule, setActiveModule] = useState<LessonModule | null>(null);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [hideText, setHideText] = useState(false);
  const [isLooping, setIsLooping] = useState(false);

  // Loading/Search State
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Translations
  const t = {
    title: language === 'fr' ? 'Académie' : 'Academy',
    subtitle: language === 'fr' ? 'Le Savoir Sacré' : 'Sacred Knowledge',
    quran: language === 'fr' ? 'Coran' : 'Quran',
    hadith: language === 'fr' ? 'Hadith' : 'Hadith',
    chapters: language === 'fr' ? 'Chapitres' : 'Chapters',
    search: language === 'fr' ? 'Rechercher...' : 'Search...',
    verses: language === 'fr' ? 'versets' : 'verses',
    loading: language === 'fr' ? 'Chargement...' : 'Loading...',
    start: language === 'fr' ? 'Commencer' : 'Start',
    noAudio: language === 'fr' ? 'Audio non requis' : 'Audio not required'
  };

  // --- Initial Data Fetch (Surahs) ---
  useEffect(() => {
    const fetchSurahs = async () => {
      try {
        const cached = localStorage.getItem('academy_surahs');
        if (cached) {
          setSurahs(JSON.parse(cached));
          return;
        }
        const res = await fetch('https://api.alquran.cloud/v1/surah');
        const data = await res.json();
        if (data.code === 200) {
          setSurahs(data.data);
          localStorage.setItem('academy_surahs', JSON.stringify(data.data));
        }
      } catch (e) {
        console.error("Failed to load surahs", e);
      }
    };
    fetchSurahs();
  }, []);

  // --- Audio Logic ---
  useEffect(() => {
    if (activeModule?.type === 'quran' && audioRef.current && activeModule.content[currentIndex]) {
       audioRef.current.src = activeModule.content[currentIndex].audio;
       if (isPlaying) audioRef.current.play().catch(() => setIsPlaying(false));
    } else if (activeModule?.type === 'hadith') {
       // Stop audio for hadith
       if(audioRef.current) {
         audioRef.current.pause();
         audioRef.current.src = "";
       }
       setIsPlaying(false);
    }
  }, [currentIndex, activeModule]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;

    const handleEnded = () => {
      if (isLooping) {
        audio.currentTime = 0;
        audio.play();
      } else {
        if (currentIndex < (activeModule?.content.length || 0) - 1) {
          setCurrentIndex(c => c + 1);
        } else {
          setIsPlaying(false);
        }
      }
    };

    audio.addEventListener('ended', handleEnded);
    return () => audio.removeEventListener('ended', handleEnded);
  }, [isLooping, currentIndex, activeModule]);

  const togglePlay = () => {
    if (activeModule?.type === 'hadith') return; // No audio for Hadith

    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  // --- Loading Logic ---

  const loadSurah = async (surah: SurahDef) => {
    setLoading(true);
    try {
      const translationEdition = language === 'fr' ? 'fr.hamidullah' : 'en.sahih';

      // Fetch Text & Translation
      const resText = await fetch(`https://api.alquran.cloud/v1/surah/${surah.number}/editions/quran-uthmani,${translationEdition}`);
      const dataText = await resText.json();

      // Fetch Audio (Alafasy)
      const resAudio = await fetch(`https://api.alquran.cloud/v1/surah/${surah.number}/ar.alafasy`);
      const dataAudio = await resAudio.json();

      if (dataText.code === 200 && dataAudio.code === 200) {
        const arabicVerses = dataText.data[0].ayahs;
        const transVerses = dataText.data[1].ayahs;
        const audioVerses = dataAudio.data.ayahs;

        const content: Verse[] = arabicVerses.map((v: any, i: number) => ({
           verseNumber: v.numberInSurah,
           text: v.text,
           translation: transVerses[i].text,
           audio: audioVerses[i].audio
        }));

        const module: LessonModule = {
          id: `surah_${surah.number}`,
          type: 'quran',
          title: surah.englishName,
          subtitle: surah.name,
          description: `${surah.englishNameTranslation} • ${surah.numberOfAyahs} ${t.verses}`,
          color: 'from-emerald-500 to-teal-600',
          icon: BookOpen,
          progress: 0,
          content
        };

        setActiveModule(module);
        setCurrentIndex(0);
        setView('player');
      }
    } catch (e) {
      console.error(e);
      alert(language === 'fr' ? "Erreur de chargement" : "Error loading Surah");
    } finally {
      setLoading(false);
    }
  };

  const loadHadithChapters = async (book: BookDef) => {
    setLoading(true);
    setActiveBook(book);
    try {
      const slug = book.slugs[language === 'fr' ? 'fr' : 'en']; // This assumes mapped slugs in constant
      // Fallback for FR since api might not have 'fr-...'
      const safeSlug = language === 'fr' ? 'eng-bukhari' : slug; // Quick fix for demo, usually we check availability

      // Using English slug for structure to ensure availability, then we match content later
      const structSlug = book.slugs.en; 

      const res = await fetch(`https://cdn.jsdelivr.net/gh/fawazahmed0/hadith-api@1/editions/${structSlug}/sections.json`);
      const data = await res.json();

      const chaptersList: ChapterDef[] = Object.entries(data)
        .map(([num, title]) => ({ number: num, title: title as string }))
        .filter(c => c.number !== '0' && c.title)
        .sort((a, b) => parseFloat(a.number) - parseFloat(b.number));

      setChapters(chaptersList);
      setView('chapters');
    } catch (e) {
      console.error(e);
      alert("Error loading chapters");
    } finally {
      setLoading(false);
    }
  };

  const loadHadithContent = async (chapter: ChapterDef) => {
    if (!activeBook) return;
    setLoading(true);
    try {
      const lang = language === 'fr' ? 'fr' : 'en';
      const slugEn = activeBook.slugs.en;
      const slugAr = activeBook.slugs.ar;

      // Fetch English (or Target Lang if available)
      const resEn = await fetch(`https://cdn.jsdelivr.net/gh/fawazahmed0/hadith-api@1/editions/${slugEn}/sections/${chapter.number}.json`);
      const dataEn = await resEn.json();

      // Fetch Arabic
      const resAr = await fetch(`https://cdn.jsdelivr.net/gh/fawazahmed0/hadith-api@1/editions/${slugAr}/sections/${chapter.number}.json`);
      let dataAr = { hadiths: [] };
      if (resAr.ok) dataAr = await resAr.json();

      const content: Verse[] = dataEn.hadiths.map((h: any) => {
        const arHadith = dataAr.hadiths.find((a: any) => a.hadithnumber === h.hadithnumber);
        return {
          verseNumber: h.hadithnumber,
          text: arHadith ? arHadith.text : '...',
          translation: h.text,
          audio: '', // No audio for Hadith
          meta: `Hadith ${h.hadithnumber}`
        };
      });

      const module: LessonModule = {
        id: `hadith_${activeBook.id}_${chapter.number}`,
        type: 'hadith',
        title: activeBook.name,
        subtitle: chapter.title,
        description: `${content.length} Hadiths`,
        color: 'from-indigo-500 to-violet-600',
        icon: Quote,
        progress: 0,
        content
      };

      setActiveModule(module);
      setCurrentIndex(0);
      setView('player');

    } catch (e) {
      console.error(e);
      alert("Error loading hadiths");
    } finally {
      setLoading(false);
    }
  };

  // --- Filtering ---
  const filteredSurahs = surahs.filter(s => 
    s.englishName.toLowerCase().includes(searchTerm.toLowerCase()) || 
    s.englishNameTranslation.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const filteredChapters = chapters.filter(c => 
    c.title.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // --- Render Player ---
  if (view === 'player' && activeModule) {
    const currentItem = activeModule.content[currentIndex];
    const progressPercent = ((currentIndex + 1) / activeModule.content.length) * 100;
    const isHadith = activeModule.type === 'hadith';

    return (
      <div className="h-full flex flex-col bg-slate-900 animate-fade-in relative overflow-hidden">
        <audio ref={audioRef} />

        {/* Background & Decor */}
        <div className={`absolute top-0 inset-x-0 h-[60%] bg-gradient-to-b ${activeModule.color} opacity-20 pointer-events-none`}></div>
        <div className="absolute top-0 right-0 w-64 h-64 bg-emerald-500 rounded-full mix-blend-multiply filter blur-3xl opacity-10 animate-pulse-slow"></div>

        {/* Header */}
        <div className="relative z-10 p-6 flex items-center justify-between">
           <button 
             onClick={() => {
                setIsPlaying(false);
                setView(isHadith ? 'chapters' : 'dashboard');
             }}
             className="w-10 h-10 rounded-full bg-white/10 backdrop-blur-md flex items-center justify-center text-white hover:bg-white/20 transition-colors"
           >
             <ArrowLeft size={20} />
           </button>
           <div className="text-center max-w-[200px]">
              <h2 className="text-white font-bold text-lg truncate">{activeModule.title}</h2>
              <p className="text-slate-300 text-xs truncate">{activeModule.subtitle} • {currentIndex + 1}/{activeModule.content.length}</p>
           </div>
           <button 
             onClick={() => setHideText(!hideText)}
             className={`w-10 h-10 rounded-full flex items-center justify-center transition-colors ${hideText ? 'bg-emerald-500 text-white' : 'bg-white/10 text-slate-300'}`}
             title={isHadith ? "Toggle Text" : t.noAudio}
           >
             {hideText ? <EyeOff size={20} /> : <Eye size={20} />}
           </button>
        </div>

        {/* Content Area */}
        <div className="flex-1 flex flex-col items-center justify-center p-6 text-center relative z-10 overflow-y-auto">
           <div className="w-full max-w-sm bg-white/5 backdrop-blur-lg border border-white/10 rounded-[2rem] p-8 shadow-2xl relative transition-all duration-500 min-h-[400px] flex flex-col justify-center">

               <div className="absolute -top-6 left-1/2 -translate-x-1/2 w-12 h-12 rounded-xl bg-slate-800 border border-slate-700 flex items-center justify-center shadow-xl">
                  {React.createElement(activeModule.icon, { size: 20, className: "text-emerald-400" })}
               </div>

               {currentItem ? (
                   <div className="mt-4 space-y-6">
                       <div className={`transition-all duration-500 ${hideText ? 'blur-md select-none opacity-50' : 'blur-0 opacity-100'}`}>
                           <p className={`font-arabic text-white leading-[2.2] drop-shadow-lg ${isHadith ? 'text-2xl text-right' : 'text-3xl text-center'}`} dir="rtl">
                               {currentItem.text}
                           </p>
                       </div>

                       <div className={`transition-all duration-500 delay-100 border-t border-white/10 pt-6 ${hideText ? 'opacity-0 translate-y-4' : 'opacity-100 translate-y-0'}`}>
                           <p className="text-slate-300 text-lg leading-relaxed font-medium">
                               {currentItem.translation}
                           </p>
                           {currentItem.meta && (
                             <span className="block mt-2 text-xs text-emerald-400 uppercase tracking-widest">{currentItem.meta}</span>
                           )}
                       </div>
                   </div>
               ) : (
                   <div className="text-white">End of Module</div>
               )}
           </div>
        </div>

        {/* Controls */}
        <div className="relative z-10 bg-slate-950/80 backdrop-blur-xl border-t border-white/5 p-6 pb-12 rounded-t-[2.5rem]">
            {/* Progress Bar */}
            <div className="mb-8">
               <div className="h-1.5 w-full bg-slate-800 rounded-full overflow-hidden">
                   <div className="h-full bg-emerald-500 transition-all duration-500 ease-out" style={{ width: `${progressPercent}%` }}></div>
               </div>
            </div>

            <div className="flex items-center justify-between max-w-xs mx-auto">
               <button 
                  onClick={() => setIsLooping(!isLooping)}
                  className={`p-3 rounded-full transition-colors ${isLooping ? 'text-emerald-400 bg-emerald-400/10' : 'text-slate-500 hover:text-slate-300'}`}
                  disabled={isHadith}
               >
                  {!isHadith && <Repeat size={20} />}
               </button>

               <div className="flex items-center gap-6">
                   <button 
                     onClick={() => setCurrentIndex(c => Math.max(0, c - 1))}
                     disabled={currentIndex === 0}
                     className="p-3 rounded-full text-white disabled:opacity-30 hover:bg-white/10 transition-colors"
                   >
                     <ChevronRight size={28} className="rotate-180" />
                   </button>

                   {/* Play Button - Only active for Quran */}
                   <button 
                     onClick={togglePlay}
                     disabled={isHadith}
                     className={`w-20 h-20 rounded-full flex items-center justify-center text-white shadow-lg transition-all ${isHadith ? 'bg-slate-800 opacity-50 cursor-default' : 'bg-gradient-to-tr from-emerald-500 to-teal-400 shadow-emerald-500/30 hover:scale-105 active:scale-95'}`}
                   >
                      {isHadith ? (
                         <BookOpen size={28} className="opacity-50" />
                      ) : (
                         isPlaying ? <Pause size={32} fill="currentColor" /> : <Play size={32} fill="currentColor" className="ml-1" />
                      )}
                   </button>

                   <button 
                     onClick={() => setCurrentIndex(c => Math.min(activeModule.content.length - 1, c + 1))}
                     disabled={currentIndex === activeModule.content.length - 1}
                     className="p-3 rounded-full text-white disabled:opacity-30 hover:bg-white/10 transition-colors"
                   >
                     <ChevronRight size={28} />
                   </button>
               </div>

               <button className="p-3 rounded-full text-slate-500 hover:text-slate-300" disabled={isHadith}>
                  {!isHadith && <Volume2 size={20} />}
               </button>
            </div>
        </div>
      </div>
    );
  }

  // --- DASHBOARD & LIST VIEWS ---
  return (
    <div className="h-full flex flex-col bg-slate-50 dark:bg-slate-950 animate-fade-in">
      {/* Header */}
      <header className="p-6 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 sticky top-0 z-20">
        <div className="flex items-center justify-between mb-4">
           {view === 'chapters' ? (
              <div className="flex items-center gap-3">
                 <button onClick={() => setView('dashboard')} className="p-2 -ml-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800">
                    <ArrowLeft size={20} className="text-slate-600 dark:text-slate-300" />
                 </button>
                 <div>
                    <h1 className="text-xl font-bold text-slate-800 dark:text-slate-100">{activeBook?.name}</h1>
                    <p className="text-xs text-slate-500 dark:text-slate-400">{t.chapters}</p>
                 </div>
              </div>
           ) : (
              <div className="flex items-center gap-3">
                 <div className="w-10 h-10 bg-emerald-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-emerald-600/30">
                    <GraduationCap size={24} />
                 </div>
                 <div>
                    <h1 className="text-2xl font-bold text-slate-800 dark:text-slate-100">{t.title}</h1>
                    <p className="text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wider">{t.subtitle}</p>
                 </div>
              </div>
           )}

           <button 
             onClick={() => onNavigate('quiz-basics')}
             className="w-10 h-10 rounded-full bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 flex items-center justify-center text-emerald-600 dark:text-emerald-400 shadow-sm"
           >
              <Brain size={20} />
           </button>
        </div>

        {/* Search & Tabs (Only on dashboard) */}
        {view === 'dashboard' && (
          <div className="space-y-4">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
              <input 
                 type="text"
                 placeholder={t.search}
                 value={searchTerm}
                 onChange={(e) => setSearchTerm(e.target.value)}
                 className="w-full bg-slate-100 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl py-2.5 pl-9 pr-4 text-sm outline-none focus:ring-2 focus:ring-emerald-500/20"
              />
            </div>

            <div className="flex p-1 bg-slate-100 dark:bg-slate-950 rounded-xl">
               <button 
                 onClick={() => setActiveTab('quran')}
                 className={`flex-1 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'quran' ? 'bg-white dark:bg-slate-800 text-emerald-600 shadow-sm' : 'text-slate-500 dark:text-slate-400'}`}
               >
                 {t.quran}
               </button>
               <button 
                 onClick={() => setActiveTab('hadith')}
                 className={`flex-1 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'hadith' ? 'bg-white dark:bg-slate-800 text-indigo-600 shadow-sm' : 'text-slate-500 dark:text-slate-400'}`}
               >
                 {t.hadith}
               </button>
            </div>
          </div>
        )}
      </header>

      {/* Content Lists */}
      <div className="flex-1 overflow-y-auto p-4 pb-24">
         {loading ? (
             <div className="flex flex-col items-center justify-center py-20">
                 <Loader2 size={32} className="animate-spin text-emerald-500 mb-2" />
                 <p className="text-slate-400 text-sm">{t.loading}</p>
             </div>
         ) : view === 'dashboard' ? (
             activeTab === 'quran' ? (
                 // Quran List
                 <div className="space-y-3">
                     {filteredSurahs.map(surah => (
                        <button 
                          key={surah.number}
                          onClick={() => loadSurah(surah)}
                          className="w-full bg-white dark:bg-slate-900 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 flex items-center justify-between hover:border-emerald-200 dark:hover:border-emerald-800 transition-all group shadow-sm"
                        >
                            <div className="flex items-center gap-4">
                               <div className="w-10 h-10 rounded-lg bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400 flex items-center justify-center font-bold text-sm">
                                  {surah.number}
                               </div>
                               <div className="text-left">
                                  <h3 className="font-bold text-slate-800 dark:text-slate-100">{surah.englishName}</h3>
                                  <p className="text-xs text-slate-500 dark:text-slate-400">{surah.englishNameTranslation} • {surah.numberOfAyahs} {t.verses}</p>
                               </div>
                            </div>
                            <span className="font-arabic text-lg text-emerald-600/80 dark:text-emerald-400/80 group-hover:scale-110 transition-transform">
                               {surah.name.replace('سُورَةُ ', '')}
                            </span>
                        </button>
                     ))}
                 </div>
             ) : (
                 // Hadith Books List
                 <div className="grid gap-3">
                     {HADITH_BOOKS.map(book => (
                        <button 
                          key={book.id}
                          onClick={() => loadHadithChapters(book)}
                          className="w-full bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-100 dark:border-slate-800 flex items-center justify-between hover:border-indigo-200 dark:hover:border-indigo-800 transition-all shadow-sm group"
                        >
                            <div className="flex items-center gap-4">
                               <div className="w-12 h-12 rounded-full bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400 flex items-center justify-center">
                                  <Quote size={20} />
                               </div>
                               <div className="text-left">
                                  <h3 className="font-bold text-slate-800 dark:text-slate-100 group-hover:text-indigo-600 dark:group-hover:text-indigo-400 transition-colors">{book.name}</h3>
                                  <p className="text-xs text-slate-500 dark:text-slate-400">Authentic Collection</p>
                               </div>
                            </div>
                            <span className="font-arabic text-lg text-slate-400 dark:text-slate-600">{book.arabicName}</span>
                        </button>
                     ))}
                 </div>
             )
         ) : view === 'chapters' ? (
             // Chapters List
             <div className="space-y-2">
                 {filteredChapters.map(chapter => (
                    <button 
                       key={chapter.number}
                       onClick={() => loadHadithContent(chapter)}
                       className="w-full bg-white dark:bg-slate-900 p-4 rounded-xl border border-slate-100 dark:border-slate-800 flex items-center gap-4 hover:border-indigo-200 dark:hover:border-indigo-800 transition-all text-left"
                    >
                        <span className="text-xs font-bold text-slate-400 w-8">{chapter.number}</span>
                        <span className="font-medium text-slate-700 dark:text-slate-200 flex-1">{chapter.title}</span>
                        <ChevronRight size={16} className="text-slate-300" />
                    </button>
                 ))}
             </div>
         ) : null}
      </div>
    </div>
  );
};

export default Academy;

import React, { useState, useRef, useEffect } from 'react';
import { 
  GraduationCap, Play, Pause, ChevronRight, BookOpen, 
  Repeat, Eye, EyeOff, Volume2, ArrowLeft, Star, 
  CheckCircle2, Brain, Sparkles, LayoutGrid, Quote,
  Search, Loader2, List
} from 'lucide-react';

interface AcademyProps {
  onNavigate: (tab: string) => void;
  language?: string;
}

// --- Types ---

interface Verse {
  text: string;
  translation: string;
  transliteration?: string; // Added transliteration
  audio: string;
  verseNumber: number;
  meta?: string;
}

interface LessonModule {
  id: string;
  type: 'quran' | 'hadith';
  title: string;
  subtitle: string;
  description: string;
  color: string;
  icon: React.ElementType;
  progress: number;
  content: Verse[];
}

interface SurahDef {
  number: number;
  name: string;
  englishName: string;
  englishNameTranslation: string;
  numberOfAyahs: number;
}

interface BookDef {
  id: string;
  name: string;
  arabicName: string;
  slugs: { en: string; fr: string; ar: string };
}

interface ChapterDef {
  number: string;
  title: string;
}

// --- Constants ---

const HADITH_BOOKS: BookDef[] = [
  { id: 'bukhari', name: 'Sahih al-Bukhari', arabicName: 'صحيح البخاري', slugs: { en: 'eng-bukhari', fr: 'eng-bukhari', ar: 'ara-bukhari' } },
  { id: 'muslim', name: 'Sahih Muslim', arabicName: 'صحيح مسلم', slugs: { en: 'eng-muslim', fr: 'eng-muslim', ar: 'ara-muslim' } },
  { id: 'nasai', name: 'Sunan an-Nasa\'i', arabicName: 'سنن النسائي', slugs: { en: 'eng-nasai', fr: 'eng-nasai', ar: 'ara-nasai' } },
  { id: 'abudawud', name: 'Sunan Abu Dawud', arabicName: 'سنن أبي داود', slugs: { en: 'eng-abudawud', fr: 'eng-abudawud', ar: 'ara-abudawud' } },
  { id: 'tirmidhi', name: 'Jami\' at-Tirmidhi', arabicName: 'جامع الترمذي', slugs: { en: 'eng-tirmidhi', fr: 'eng-tirmidhi', ar: 'ara-tirmidhi' } },
  { id: 'ibnmajah', name: 'Sunan Ibn Majah', arabicName: 'سنن ابن ماجه', slugs: { en: 'eng-ibnmajah', fr: 'eng-ibnmajah', ar: 'ara-ibnmajah' } },
  { id: 'malik', name: 'Muwatta Malik', arabicName: 'موطأ مالك', slugs: { en: 'eng-malik', fr: 'eng-malik', ar: 'ara-malik' } },
];

const Academy: React.FC<AcademyProps> = ({ onNavigate, language = 'en' }) => {
  // View State
  const [activeTab, setActiveTab] = useState<'quran' | 'hadith'>('quran');
  const [view, setView] = useState<'dashboard' | 'chapters' | 'player'>('dashboard');

  // Data State
  const [surahs, setSurahs] = useState<SurahDef[]>([]);
  const [activeBook, setActiveBook] = useState<BookDef | null>(null);
  const [chapters, setChapters] = useState<ChapterDef[]>([]);

  // Player State
  const [activeModule, setActiveModule] = useState<LessonModule | null>(null);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [hideText, setHideText] = useState(false);
  const [isLooping, setIsLooping] = useState(false);

  // Loading/Search State
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Translations
  const t = {
    title: language === 'fr' ? 'Académie' : 'Academy',
    subtitle: language === 'fr' ? 'Le Savoir Sacré' : 'Sacred Knowledge',
    quran: language === 'fr' ? 'Coran' : 'Quran',
    hadith: language === 'fr' ? 'Hadith' : 'Hadith',
    chapters: language === 'fr' ? 'Chapitres' : 'Chapters',
    search: language === 'fr' ? 'Rechercher...' : 'Search...',
    verses: language === 'fr' ? 'versets' : 'verses',
    loading: language === 'fr' ? 'Chargement...' : 'Loading...',
    start: language === 'fr' ? 'Commencer' : 'Start',
    noAudio: language === 'fr' ? 'Audio non requis' : 'Audio not required'
  };

  // --- Initial Data Fetch (Surahs) ---
  useEffect(() => {
    const fetchSurahs = async () => {
      try {
        const cached = localStorage.getItem('academy_surahs');
        if (cached) {
          setSurahs(JSON.parse(cached));
          return;
        }
        const res = await fetch('https://api.alquran.cloud/v1/surah');
        const data = await res.json();
        if (data.code === 200) {
          setSurahs(data.data);
          localStorage.setItem('academy_surahs', JSON.stringify(data.data));
        }
      } catch (e) {
        console.error("Failed to load surahs", e);
      }
    };
    fetchSurahs();
  }, []);

  // --- Audio Logic ---
  useEffect(() => {
    if (activeModule?.type === 'quran' && audioRef.current && activeModule.content[currentIndex]) {
       audioRef.current.src = activeModule.content[currentIndex].audio;
       if (isPlaying) audioRef.current.play().catch(() => setIsPlaying(false));
    } else if (activeModule?.type === 'hadith') {
       // Stop audio for hadith
       if(audioRef.current) {
         audioRef.current.pause();
         audioRef.current.src = "";
       }
       setIsPlaying(false);
    }
  }, [currentIndex, activeModule]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;

    const handleEnded = () => {
      if (isLooping) {
        audio.currentTime = 0;
        audio.play();
      } else {
        if (currentIndex < (activeModule?.content.length || 0) - 1) {
          setCurrentIndex(c => c + 1);
        } else {
          setIsPlaying(false);
        }
      }
    };

    audio.addEventListener('ended', handleEnded);
    return () => audio.removeEventListener('ended', handleEnded);
  }, [isLooping, currentIndex, activeModule]);

  const togglePlay = () => {
    if (activeModule?.type === 'hadith') return; // No audio for Hadith

    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  // --- Loading Logic ---

  const loadSurah = async (surah: SurahDef) => {
    setLoading(true);
    try {
      const translationEdition = language === 'fr' ? 'fr.hamidullah' : 'en.sahih';

      // Fetch Text, Translation AND Transliteration
      // Index 0: Arabic, Index 1: Translation, Index 2: Transliteration
      const resText = await fetch(`https://api.alquran.cloud/v1/surah/${surah.number}/editions/quran-uthmani,${translationEdition},en.transliteration`);
      const dataText = await resText.json();

      // Fetch Audio (Alafasy)
      const resAudio = await fetch(`https://api.alquran.cloud/v1/surah/${surah.number}/ar.alafasy`);
      const dataAudio = await resAudio.json();

      if (dataText.code === 200 && dataAudio.code === 200) {
        const arabicVerses = dataText.data[0].ayahs;
        const transVerses = dataText.data[1].ayahs;
        const translitVerses = dataText.data[2].ayahs;
        const audioVerses = dataAudio.data.ayahs;

        const content: Verse[] = arabicVerses.map((v: any, i: number) => ({
           verseNumber: v.numberInSurah,
           text: v.text,
           translation: transVerses[i].text,
           transliteration: translitVerses[i].text,
           audio: audioVerses[i].audio
        }));

        const module: LessonModule = {
          id: `surah_${surah.number}`,
          type: 'quran',
          title: surah.englishName,
          subtitle: surah.name,
          description: `${surah.englishNameTranslation} • ${surah.numberOfAyahs} ${t.verses}`,
          color: 'from-emerald-500 to-teal-600',
          icon: BookOpen,
          progress: 0,
          content
        };

        setActiveModule(module);
        setCurrentIndex(0);
        setView('player');
      }
    } catch (e) {
      console.error(e);
      alert(language === 'fr' ? "Erreur de chargement" : "Error loading Surah");
    } finally {
      setLoading(false);
    }
  };

  const loadHadithChapters = async (book: BookDef) => {
    setLoading(true);
    setActiveBook(book);
    try {
      const slug = book.slugs[language === 'fr' ? 'fr' : 'en']; // This assumes mapped slugs in constant
      // Fallback for FR since api might not have 'fr-...'
      const safeSlug = language === 'fr' ? 'eng-bukhari' : slug; // Quick fix for demo, usually we check availability

      // Using English slug for structure to ensure availability, then we match content later
      const structSlug = book.slugs.en; 

      const res = await fetch(`https://cdn.jsdelivr.net/gh/fawazahmed0/hadith-api@1/editions/${structSlug}/sections.json`);
      const data = await res.json();

      const chaptersList: ChapterDef[] = Object.entries(data)
        .map(([num, title]) => ({ number: num, title: title as string }))
        .filter(c => c.number !== '0' && c.title)
        .sort((a, b) => parseFloat(a.number) - parseFloat(b.number));

      setChapters(chaptersList);
      setView('chapters');
    } catch (e) {
      console.error(e);
      alert("Error loading chapters");
    } finally {
      setLoading(false);
    }
  };

  const loadHadithContent = async (chapter: ChapterDef) => {
    if (!activeBook) return;
    setLoading(true);
    try {
      const lang = language === 'fr' ? 'fr' : 'en';
      const slugEn = activeBook.slugs.en;
      const slugAr = activeBook.slugs.ar;

      // Fetch English (or Target Lang if available)
      const resEn = await fetch(`https://cdn.jsdelivr.net/gh/fawazahmed0/hadith-api@1/editions/${slugEn}/sections/${chapter.number}.json`);
      const dataEn = await resEn.json();

      // Fetch Arabic
      const resAr = await fetch(`https://cdn.jsdelivr.net/gh/fawazahmed0/hadith-api@1/editions/${slugAr}/sections/${chapter.number}.json`);
      let dataAr = { hadiths: [] };
      if (resAr.ok) dataAr = await resAr.json();

      const content: Verse[] = dataEn.hadiths.map((h: any) => {
        const arHadith = dataAr.hadiths.find((a: any) => a.hadithnumber === h.hadithnumber);
        return {
          verseNumber: h.hadithnumber,
          text: arHadith ? arHadith.text : '...',
          translation: h.text,
          audio: '', // No audio for Hadith
          meta: `Hadith ${h.hadithnumber}`
        };
      });

      const module: LessonModule = {
        id: `hadith_${activeBook.id}_${chapter.number}`,
        type: 'hadith',
        title: activeBook.name,
        subtitle: chapter.title,
        description: `${content.length} Hadiths`,
        color: 'from-indigo-500 to-violet-600',
        icon: Quote,
        progress: 0,
        content
      };

      setActiveModule(module);
      setCurrentIndex(0);
      setView('player');

    } catch (e) {
      console.error(e);
      alert("Error loading hadiths");
    } finally {
      setLoading(false);
    }
  };

  // --- Filtering ---
  const filteredSurahs = surahs.filter(s => 
    s.englishName.toLowerCase().includes(searchTerm.toLowerCase()) || 
    s.englishNameTranslation.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const filteredChapters = chapters.filter(c => 
    c.title.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // --- Render Player ---
  if (view === 'player' && activeModule) {
    const currentItem = activeModule.content[currentIndex];
    const progressPercent = ((currentIndex + 1) / activeModule.content.length) * 100;
    const isHadith = activeModule.type === 'hadith';

    return (
      <div className="h-full flex flex-col bg-slate-900 animate-fade-in relative overflow-hidden">
        <audio ref={audioRef} />

        {/* Background & Decor */}
        <div className={`absolute top-0 inset-x-0 h-[60%] bg-gradient-to-b ${activeModule.color} opacity-20 pointer-events-none`}></div>
        <div className="absolute top-0 right-0 w-64 h-64 bg-emerald-500 rounded-full mix-blend-multiply filter blur-3xl opacity-10 animate-pulse-slow"></div>

        {/* Header */}
        <div className="relative z-10 p-6 flex items-center justify-between">
           <button 
             onClick={() => {
                setIsPlaying(false);
                setView(isHadith ? 'chapters' : 'dashboard');
             }}
             className="w-10 h-10 rounded-full bg-white/10 backdrop-blur-md flex items-center justify-center text-white hover:bg-white/20 transition-colors"
           >
             <ArrowLeft size={20} />
           </button>
           <div className="text-center max-w-[200px]">
              <h2 className="text-white font-bold text-lg truncate">{activeModule.title}</h2>
              <p className="text-slate-300 text-xs truncate">{activeModule.subtitle} • {currentIndex + 1}/{activeModule.content.length}</p>
           </div>
           <button 
             onClick={() => setHideText(!hideText)}
             className={`w-10 h-10 rounded-full flex items-center justify-center transition-colors ${hideText ? 'bg-emerald-500 text-white' : 'bg-white/10 text-slate-300'}`}
             title={isHadith ? "Toggle Text" : t.noAudio}
           >
             {hideText ? <EyeOff size={20} /> : <Eye size={20} />}
           </button>
        </div>

        {/* Content Area */}
        <div className="flex-1 flex flex-col items-center justify-center p-6 text-center relative z-10 overflow-y-auto">
           <div className="w-full max-w-sm bg-white/5 backdrop-blur-lg border border-white/10 rounded-[2rem] p-8 shadow-2xl relative transition-all duration-500 min-h-[400px] flex flex-col justify-center">

               <div className="absolute -top-6 left-1/2 -translate-x-1/2 w-12 h-12 rounded-xl bg-slate-800 border border-slate-700 flex items-center justify-center shadow-xl">
                  {React.createElement(activeModule.icon, { size: 20, className: "text-emerald-400" })}
               </div>

               {currentItem ? (
                   <div className="mt-4 space-y-6">
                       <div className={`transition-all duration-500 ${hideText ? 'blur-md select-none opacity-50' : 'blur-0 opacity-100'}`}>
                           <p className={`font-arabic text-white leading-[2.2] drop-shadow-lg ${isHadith ? 'text-2xl text-right' : 'text-3xl text-center'}`} dir="rtl">
                               {currentItem.text}
                           </p>
                       </div>

                       {/* Transliteration (Only for Quran) */}
                       {currentItem.transliteration && !isHadith && (
                           <div className={`transition-all duration-500 delay-75 ${hideText ? 'opacity-0 translate-y-2' : 'opacity-100 translate-y-0'}`}>
                               <p className="text-amber-400/90 text-sm italic font-medium leading-relaxed tracking-wide">
                                   {currentItem.transliteration}
                               </p>
                           </div>
                       )}

                       <div className={`transition-all duration-500 delay-100 border-t border-white/10 pt-6 ${hideText ? 'opacity-0 translate-y-4' : 'opacity-100 translate-y-0'}`}>
                           <p className="text-slate-300 text-lg leading-relaxed font-medium">
                               {currentItem.translation}
                           </p>
                           {currentItem.meta && (
                             <span className="block mt-2 text-xs text-emerald-400 uppercase tracking-widest">{currentItem.meta}</span>
                           )}
                       </div>
                   </div>
               ) : (
                   <div className="text-white">End of Module</div>
               )}
           </div>
        </div>

        {/* Controls */}
        <div className="relative z-10 bg-slate-950/80 backdrop-blur-xl border-t border-white/5 p-6 pb-12 rounded-t-[2.5rem]">
            {/* Progress Bar */}
            <div className="mb-8">
               <div className="h-1.5 w-full bg-slate-800 rounded-full overflow-hidden">
                   <div className="h-full bg-emerald-500 transition-all duration-500 ease-out" style={{ width: `${progressPercent}%` }}></div>
               </div>
            </div>

            <div className="flex items-center justify-between max-w-xs mx-auto">
               <button 
                  onClick={() => setIsLooping(!isLooping)}
                  className={`p-3 rounded-full transition-colors ${isLooping ? 'text-emerald-400 bg-emerald-400/10' : 'text-slate-500 hover:text-slate-300'}`}
                  disabled={isHadith}
               >
                  {!isHadith && <Repeat size={20} />}
               </button>

               <div className="flex items-center gap-6">
                   <button 
                     onClick={() => setCurrentIndex(c => Math.max(0, c - 1))}
                     disabled={currentIndex === 0}
                     className="p-3 rounded-full text-white disabled:opacity-30 hover:bg-white/10 transition-colors"
                   >
                     <ChevronRight size={28} className="rotate-180" />
                   </button>

                   {/* Play Button - Only active for Quran */}
                   <button 
                     onClick={togglePlay}
                     disabled={isHadith}
                     className={`w-20 h-20 rounded-full flex items-center justify-center text-white shadow-lg transition-all ${isHadith ? 'bg-slate-800 opacity-50 cursor-default' : 'bg-gradient-to-tr from-emerald-500 to-teal-400 shadow-emerald-500/30 hover:scale-105 active:scale-95'}`}
                   >
                      {isHadith ? (
                         <BookOpen size={28} className="opacity-50" />
                      ) : (
                         isPlaying ? <Pause size={32} fill="currentColor" /> : <Play size={32} fill="currentColor" className="ml-1" />
                      )}
                   </button>

                   <button 
                     onClick={() => setCurrentIndex(c => Math.min(activeModule.content.length - 1, c + 1))}
                     disabled={currentIndex === activeModule.content.length - 1}
                     className="p-3 rounded-full text-white disabled:opacity-30 hover:bg-white/10 transition-colors"
                   >
                     <ChevronRight size={28} />
                   </button>
               </div>

               <button className="p-3 rounded-full text-slate-500 hover:text-slate-300" disabled={isHadith}>
                  {!isHadith && <Volume2 size={20} />}
               </button>
            </div>
        </div>
      </div>
    );
  }

  // --- DASHBOARD & LIST VIEWS ---
  return (
    <div className="h-full flex flex-col bg-slate-50 dark:bg-slate-950 animate-fade-in">
      {/* Header */}
      <header className="p-6 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 sticky top-0 z-20">
        <div className="flex items-center justify-between mb-4">
           {view === 'chapters' ? (
              <div className="flex items-center gap-3">
                 <button onClick={() => setView('dashboard')} className="p-2 -ml-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800">
                    <ArrowLeft size={20} className="text-slate-600 dark:text-slate-300" />
                 </button>
                 <div>
                    <h1 className="text-xl font-bold text-slate-800 dark:text-slate-100">{activeBook?.name}</h1>
                    <p className="text-xs text-slate-500 dark:text-slate-400">{t.chapters}</p>
                 </div>
              </div>
           ) : (
              <div className="flex items-center gap-3">
                 <div className="w-10 h-10 bg-emerald-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-emerald-600/30">
                    <GraduationCap size={24} />
                 </div>
                 <div>
                    <h1 className="text-2xl font-bold text-slate-800 dark:text-slate-100">{t.title}</h1>
                    <p className="text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wider">{t.subtitle}</p>
                 </div>
              </div>
           )}

           <button 
             onClick={() => onNavigate('quiz-basics')}
             className="w-10 h-10 rounded-full bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 flex items-center justify-center text-emerald-600 dark:text-emerald-400 shadow-sm"
           >
              <Brain size={20} />
           </button>
        </div>

        {/* Search & Tabs (Only on dashboard) */}
        {view === 'dashboard' && (
          <div className="space-y-4">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
              <input 
                 type="text"
                 placeholder={t.search}
                 value={searchTerm}
                 onChange={(e) => setSearchTerm(e.target.value)}
                 className="w-full bg-slate-100 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl py-2.5 pl-9 pr-4 text-sm outline-none focus:ring-2 focus:ring-emerald-500/20"
              />
            </div>

            <div className="flex p-1 bg-slate-100 dark:bg-slate-950 rounded-xl">
               <button 
                 onClick={() => setActiveTab('quran')}
                 className={`flex-1 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'quran' ? 'bg-white dark:bg-slate-800 text-emerald-600 shadow-sm' : 'text-slate-500 dark:text-slate-400'}`}
               >
                 {t.quran}
               </button>
               <button 
                 onClick={() => setActiveTab('hadith')}
                 className={`flex-1 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'hadith' ? 'bg-white dark:bg-slate-800 text-indigo-600 shadow-sm' : 'text-slate-500 dark:text-slate-400'}`}
               >
                 {t.hadith}
               </button>
            </div>
          </div>
        )}
      </header>

      {/* Content Lists */}
      <div className="flex-1 overflow-y-auto p-4 pb-24">
         {loading ? (
             <div className="flex flex-col items-center justify-center py-20">
                 <Loader2 size={32} className="animate-spin text-emerald-500 mb-2" />
                 <p className="text-slate-400 text-sm">{t.loading}</p>
             </div>
         ) : view === 'dashboard' ? (
             activeTab === 'quran' ? (
                 // Quran List
                 <div className="space-y-3">
                     {filteredSurahs.map(surah => (
                        <button 
                          key={surah.number}
                          onClick={() => loadSurah(surah)}
                          className="w-full bg-white dark:bg-slate-900 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 flex items-center justify-between hover:border-emerald-200 dark:hover:border-emerald-800 transition-all group shadow-sm"
                        >
                            <div className="flex items-center gap-4">
                               <div className="w-10 h-10 rounded-lg bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400 flex items-center justify-center font-bold text-sm">
                                  {surah.number}
                               </div>
                               <div className="text-left">
                                  <h3 className="font-bold text-slate-800 dark:text-slate-100">{surah.englishName}</h3>
                                  <p className="text-xs text-slate-500 dark:text-slate-400">{surah.englishNameTranslation} • {surah.numberOfAyahs} {t.verses}</p>
                               </div>
                            </div>
                            <span className="font-arabic text-lg text-emerald-600/80 dark:text-emerald-400/80 group-hover:scale-110 transition-transform">
                               {surah.name.replace('سُورَةُ ', '')}
                            </span>
                        </button>
                     ))}
                 </div>
             ) : (
                 // Hadith Books List
                 <div className="grid gap-3">
                     {HADITH_BOOKS.map(book => (
                        <button 
                          key={book.id}
                          onClick={() => loadHadithChapters(book)}
                          className="w-full bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-100 dark:border-slate-800 flex items-center justify-between hover:border-indigo-200 dark:hover:border-indigo-800 transition-all shadow-sm group"
                        >
                            <div className="flex items-center gap-4">
                               <div className="w-12 h-12 rounded-full bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400 flex items-center justify-center">
                                  <Quote size={20} />
                               </div>
                               <div className="text-left">
                                  <h3 className="font-bold text-slate-800 dark:text-slate-100 group-hover:text-indigo-600 dark:group-hover:text-indigo-400 transition-colors">{book.name}</h3>
                                  <p className="text-xs text-slate-500 dark:text-slate-400">Authentic Collection</p>
                               </div>
                            </div>
                            <span className="font-arabic text-lg text-slate-400 dark:text-slate-600">{book.arabicName}</span>
                        </button>
                     ))}
                 </div>
             )
         ) : view === 'chapters' ? (
             // Chapters List
             <div className="space-y-2">
                 {filteredChapters.map(chapter => (
                    <button 
                       key={chapter.number}
                       onClick={() => loadHadithContent(chapter)}
                       className="w-full bg-white dark:bg-slate-900 p-4 rounded-xl border border-slate-100 dark:border-slate-800 flex items-center gap-4 hover:border-indigo-200 dark:hover:border-indigo-800 transition-all text-left"
                    >
                        <span className="text-xs font-bold text-slate-400 w-8">{chapter.number}</span>
                        <span className="font-medium text-slate-700 dark:text-slate-200 flex-1">{chapter.title}</span>
                        <ChevronRight size={16} className="text-slate-300" />
                    </button>
                 ))}
             </div>
         ) : null}
      </div>
    </div>
  );
};

export default Academy;

