             <span className="inline-flex items-center gap-2 text-xs font-bold uppercase tracking-widest opacity-80 mb-2">
                <Feather size={14} /> Story of the Day
             </span>
             <h2 className="text-2xl font-bold leading-tight line-clamp-2">{story.title}</h2>
             <span className="text-xs bg-white/20 px-2 py-1 rounded-full self-start mt-2 backdrop-blur-sm">{story.theme}</span>
          </div>
       </div>

       <div className="p-6">
          {/* Main Story */}
          <div className={`relative transition-all duration-500 ${expanded ? 'max-h-full' : 'max-h-32 overflow-hidden'}`}>
             <p className="text-slate-600 dark:text-slate-300 leading-relaxed text-sm whitespace-pre-line">
                {story.story}
