                    className={`px-6 py-3 rounded-full text-white font-bold shadow-lg bg-gradient-to-r ${activeLesson.color} active:scale-95 transition-transform`}
                 >
                    {t.lessonComplete}
                 </button>
             ) : (
                 <button 
                    onClick={() => setCurrentIndex(c => Math.min(slides.length - 1, c + 1))}
