const Academy: React.FC<AcademyProps> = ({ onNavigate, language = 'en' }) => {
  // View State
  const [activeTab, setActiveTab] = useState<'quran' | 'lessons'>('quran');
  const [view, setView] = useState<'dashboard' | 'lesson_view' | 'player'>('dashboard');

  // Data State
  const [surahs, setSurahs] = useState<SurahDef[]>([]);

  // Player State (Quran & Lessons)
  const [activeModule, setActiveModule] = useState<LessonModule | null>(null);
  const [activeLesson, setActiveLesson] = useState<Lesson | null>(null);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [hideText, setHideText] = useState(false);
  const [isLooping, setIsLooping] = useState(false);

  // Loading/Search State
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Translations
  const t = {
    title: language === 'fr' ? 'Académie' : 'Academy',
    subtitle: language === 'fr' ? 'Savoir Sacré' : 'Sacred Knowledge',
    quran: language === 'fr' ? 'Coran' : 'Quran',
    lessons: language === 'fr' ? 'Leçons' : 'Lessons',
    search: language === 'fr' ? 'Rechercher...' : 'Search...',
    verses: language === 'fr' ? 'versets' : 'verses',
    loading: language === 'fr' ? 'Chargement...' : 'Loading...',
    start: language === 'fr' ? 'Commencer' : 'Start',
    noAudio: language === 'fr' ? 'Audio non requis' : 'Audio not required',
    lessonComplete: language === 'fr' ? 'Leçon Terminée' : 'Lesson Complete',
    next: language === 'fr' ? 'Suivant' : 'Next',
    prev: language === 'fr' ? 'Précédent' : 'Previous'
  };

  // --- Initial Data Fetch (Surahs) ---
  useEffect(() => {
    const fetchSurahs = async () => {
      try {
        const cached = localStorage.getItem('academy_surahs');
        if (cached) {
          setSurahs(JSON.parse(cached));
          return;
        }
        const res = await fetch('https://api.alquran.cloud/v1/surah');
        const data = await res.json();
        if (data.code === 200) {
          setSurahs(data.data);
          localStorage.setItem('academy_surahs', JSON.stringify(data.data));
        }
      } catch (e) {
        console.error("Failed to load surahs", e);
      }
    };
    fetchSurahs();
  }, []);

  // --- Audio Logic (Quran Only) ---
  useEffect(() => {
    if (activeModule?.type === 'quran' && audioRef.current && activeModule.content[currentIndex]) {
       audioRef.current.src = activeModule.content[currentIndex].audio;
       if (isPlaying) audioRef.current.play().catch(() => setIsPlaying(false));
    }
  }, [currentIndex, activeModule]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;

    const handleEnded = () => {
      if (isLooping) {
        audio.currentTime = 0;
        audio.play();
      } else {
        if (currentIndex < (activeModule?.content.length || 0) - 1) {
          setCurrentIndex(c => c + 1);
        } else {
          setIsPlaying(false);
        }
      }
    };

    audio.addEventListener('ended', handleEnded);
    return () => audio.removeEventListener('ended', handleEnded);
  }, [isLooping, currentIndex, activeModule]);

  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  // --- Loading Logic ---

  const loadSurah = async (surah: SurahDef) => {
    setLoading(true);
    try {
      const translationEdition = language === 'fr' ? 'fr.hamidullah' : 'en.sahih';

      const resText = await fetch(`https://api.alquran.cloud/v1/surah/${surah.number}/editions/quran-uthmani,${translationEdition},en.transliteration`);
      const dataText = await resText.json();

      const resAudio = await fetch(`https://api.alquran.cloud/v1/surah/${surah.number}/ar.alafasy`);
      const dataAudio = await resAudio.json();

      if (dataText.code === 200 && dataAudio.code === 200) {
        const arabicVerses = dataText.data[0].ayahs;
        const transVerses = dataText.data[1].ayahs;
        const translitVerses = dataText.data[2].ayahs;
        const audioVerses = dataAudio.data.ayahs;

        const content: Verse[] = arabicVerses.map((v: any, i: number) => ({
           verseNumber: v.numberInSurah,
           text: v.text,
           translation: transVerses[i].text,
           transliteration: translitVerses[i].text,
           audio: audioVerses[i].audio
        }));

        const module: LessonModule = {
          id: `surah_${surah.number}`,
          type: 'quran',
          title: surah.englishName,
          subtitle: surah.name,
          description: `${surah.englishNameTranslation} • ${surah.numberOfAyahs} ${t.verses}`,
          color: 'from-emerald-500 to-teal-600',
          icon: BookOpen,
          progress: 0,
          content
        };

        setActiveModule(module);
        setActiveLesson(null);
        setCurrentIndex(0);
        setView('player');
      }
    } catch (e) {
      console.error(e);
      alert(language === 'fr' ? "Erreur de chargement" : "Error loading Surah");
    } finally {
      setLoading(false);
    }
  };

  const openLesson = (lesson: Lesson) => {
    setActiveLesson(lesson);
    setActiveModule(null);
    setCurrentIndex(0);
    setView('lesson_view');
  };

  // --- Filtering ---
  const filteredSurahs = surahs.filter(s => 
    s.englishName.toLowerCase().includes(searchTerm.toLowerCase()) || 
    s.englishNameTranslation.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const filteredLessons = LESSONS_DATA.filter(l => 
    (language === 'fr' ? l.title_fr : l.title_en).toLowerCase().includes(searchTerm.toLowerCase())
  );

  // --- Render Quran Player ---
  if (view === 'player' && activeModule) {
    const currentItem = activeModule.content[currentIndex];
    const progressPercent = ((currentIndex + 1) / activeModule.content.length) * 100;

    return (
      <div className="h-full flex flex-col bg-slate-900 animate-fade-in relative overflow-hidden">
        <audio ref={audioRef} />

        {/* Background & Decor */}
        <div className={`absolute top-0 inset-x-0 h-[60%] bg-gradient-to-b ${activeModule.color} opacity-20 pointer-events-none`}></div>
        <div className="absolute top-0 right-0 w-64 h-64 bg-emerald-500 rounded-full mix-blend-multiply filter blur-3xl opacity-10 animate-pulse-slow"></div>

        {/* Header */}
        <div className="relative z-10 p-6 flex items-center justify-between">
           <button 
             onClick={() => {
                setIsPlaying(false);
                setView('dashboard');
             }}
             className="w-10 h-10 rounded-full bg-white/10 backdrop-blur-md flex items-center justify-center text-white hover:bg-white/20 transition-colors"
           >
             <ArrowLeft size={20} />
           </button>
           <div className="text-center max-w-[200px]">
              <h2 className="text-white font-bold text-lg truncate">{activeModule.title}</h2>
              <p className="text-slate-300 text-xs truncate">{activeModule.subtitle} • {currentIndex + 1}/{activeModule.content.length}</p>
           </div>
           <button 
             onClick={() => setHideText(!hideText)}
             className={`w-10 h-10 rounded-full flex items-center justify-center transition-colors ${hideText ? 'bg-emerald-500 text-white' : 'bg-white/10 text-slate-300'}`}
           >
             {hideText ? <EyeOff size={20} /> : <Eye size={20} />}
           </button>
        </div>

        {/* Content Area */}
        <div className="flex-1 flex flex-col items-center justify-center p-6 text-center relative z-10 overflow-y-auto">
           <div className="w-full max-w-sm bg-white/5 backdrop-blur-lg border border-white/10 rounded-[2rem] p-8 shadow-2xl relative transition-all duration-500 min-h-[400px] flex flex-col justify-center">

               <div className="absolute -top-6 left-1/2 -translate-x-1/2 w-12 h-12 rounded-xl bg-slate-800 border border-slate-700 flex items-center justify-center shadow-xl">
                  {React.createElement(activeModule.icon, { size: 20, className: "text-emerald-400" })}
               </div>

               {currentItem ? (
                   <div className="mt-4 space-y-6">
                       <div className={`transition-all duration-500 ${hideText ? 'blur-md select-none opacity-50' : 'blur-0 opacity-100'}`}>
                           <p className="font-arabic text-3xl text-center text-white leading-[2.2] drop-shadow-lg" dir="rtl">
                               {currentItem.text}
                           </p>
                       </div>

                       {/* Transliteration */}
                       {currentItem.transliteration && (
                           <div className={`transition-all duration-500 delay-75 ${hideText ? 'opacity-0 translate-y-2' : 'opacity-100 translate-y-0'}`}>
                               <p className="text-amber-400/90 text-sm italic font-medium leading-relaxed tracking-wide">
                                   {currentItem.transliteration}
                               </p>
                           </div>
                       )}

                       <div className={`transition-all duration-500 delay-100 border-t border-white/10 pt-6 ${hideText ? 'opacity-0 translate-y-4' : 'opacity-100 translate-y-0'}`}>
                           <p className="text-slate-300 text-lg leading-relaxed font-medium">
                               {currentItem.translation}
                           </p>
                       </div>
                   </div>
               ) : (
                   <div className="text-white">End of Module</div>
               )}
           </div>
        </div>

        {/* Controls */}
        <div className="relative z-10 bg-slate-950/80 backdrop-blur-xl border-t border-white/5 p-6 pb-12 rounded-t-[2.5rem]">
            {/* Progress Bar */}
            <div className="mb-8">
               <div className="h-1.5 w-full bg-slate-800 rounded-full overflow-hidden">
                   <div className="h-full bg-emerald-500 transition-all duration-500 ease-out" style={{ width: `${progressPercent}%` }}></div>
               </div>
            </div>

            <div className="flex items-center justify-between max-w-xs mx-auto">
               <button 
                  onClick={() => setIsLooping(!isLooping)}
                  className={`p-3 rounded-full transition-colors ${isLooping ? 'text-emerald-400 bg-emerald-400/10' : 'text-slate-500 hover:text-slate-300'}`}
               >
                  <Repeat size={20} />
               </button>

               <div className="flex items-center gap-6">
                   <button 
                     onClick={() => setCurrentIndex(c => Math.max(0, c - 1))}
                     disabled={currentIndex === 0}
                     className="p-3 rounded-full text-white disabled:opacity-30 hover:bg-white/10 transition-colors"
                   >
                     <ChevronRight size={28} className="rotate-180" />
                   </button>

                   <button 
                     onClick={togglePlay}
                     className="w-20 h-20 rounded-full flex items-center justify-center text-white shadow-lg transition-all bg-gradient-to-tr from-emerald-500 to-teal-400 shadow-emerald-500/30 hover:scale-105 active:scale-95"
                   >
                      {isPlaying ? <Pause size={32} fill="currentColor" /> : <Play size={32} fill="currentColor" className="ml-1" />}
                   </button>

                   <button 
                     onClick={() => setCurrentIndex(c => Math.min(activeModule.content.length - 1, c + 1))}
                     disabled={currentIndex === activeModule.content.length - 1}
                     className="p-3 rounded-full text-white disabled:opacity-30 hover:bg-white/10 transition-colors"
                   >
                     <ChevronRight size={28} />
                   </button>
               </div>

               <button className="p-3 rounded-full text-slate-500 hover:text-slate-300">
                  <Volume2 size={20} />
               </button>
            </div>
        </div>
      </div>
    );
  }

  // --- Render Lesson View (Static Content) ---
  if (view === 'lesson_view' && activeLesson) {
    const slides = language === 'fr' ? activeLesson.slides_fr : activeLesson.slides_en;
    const currentSlide = slides[currentIndex];
    const progress = ((currentIndex + 1) / slides.length) * 100;

    return (
      <div className="h-full flex flex-col bg-gradient-to-b from-indigo-500 to-purple-600 animate-fade-in relative overflow-hidden text-white">

         {/* Background Particles/Noise */}
         <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/stardust.png')]"></div>

         {/* Header */}
         <div className="p-6 flex items-center justify-between sticky top-0 z-20">
            <button 
              onClick={() => setView('dashboard')}
              className="p-2 bg-white/10 rounded-full hover:bg-white/20 transition-colors backdrop-blur-md"
            >
              <ArrowLeft size={20} className="text-white" />
            </button>
            <h2 className="font-bold text-white text-sm uppercase tracking-wider">{language === 'fr' ? activeLesson.title_fr : activeLesson.title_en}</h2>
            <div className="w-8"></div>
         </div>

         {/* Content */}
         <div className="flex-1 flex flex-col px-6 pb-24 pt-4 relative z-10">
            {/* Progress Bar */}
            <div className="w-full h-1.5 bg-black/20 rounded-full mb-8 overflow-hidden backdrop-blur-sm">
                <div className="h-full bg-white transition-all duration-500" style={{ width: `${progress}%` }}></div>
            </div>

            <div className="flex-1 flex flex-col items-center justify-center text-center space-y-6 animate-fade-in-up key-{currentIndex}">

                {/* Visual Representation (SVG) */}
                <LessonVisual type={currentSlide.visual} color={activeLesson.color} />

                <h1 className="text-3xl font-bold text-white leading-tight drop-shadow-md">
                    {currentSlide.title}
                </h1>

                <div className="bg-black/10 p-6 rounded-2xl backdrop-blur-md border border-white/10">
                    <p className="text-lg text-white/90 leading-relaxed font-medium">
                        {currentSlide.content}
                    </p>
                </div>
            </div>
         </div>

         {/* Footer Nav */}
         <div className="p-6 border-t border-white/10 flex justify-between items-center sticky bottom-0 z-20 bg-black/10 backdrop-blur-xl">
             <button 
                onClick={() => setCurrentIndex(c => Math.max(0, c - 1))}
                disabled={currentIndex === 0}
                className="text-white/60 hover:text-white disabled:opacity-30 font-bold flex items-center gap-2 transition-colors"
             >
                <ArrowLeft size={18} /> {t.prev}
             </button>

             {currentIndex === slides.length - 1 ? (
                 <button 
                    onClick={() => setView('dashboard')}
                    className="px-6 py-3 rounded-full text-indigo-900 font-bold shadow-lg bg-white active:scale-95 transition-transform"
                 >
                    {t.lessonComplete}
                 </button>
             ) : (
                 <button 
                    onClick={() => setCurrentIndex(c => Math.min(slides.length - 1, c + 1))}
                    className="flex items-center gap-2 text-white font-bold hover:scale-105 transition-transform bg-white/20 px-4 py-2 rounded-full backdrop-blur-md"
                 >
                    {t.next} <ChevronRight size={18} />
                 </button>
             )}
         </div>
      </div>
    );
  }

  // --- DASHBOARD ---
  return (
    <div className="h-full flex flex-col bg-slate-50 dark:bg-slate-950 animate-fade-in">
      {/* Header */}
      <header className="p-6 bg-white dark:bg-slate-900 border-b border-slate-100 dark:border-slate-800 sticky top-0 z-20">
        <div className="flex items-center justify-between mb-4">
           <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-emerald-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-emerald-600/30">
                 <GraduationCap size={24} />
              </div>
              <div>
                 <h1 className="text-2xl font-bold text-slate-800 dark:text-slate-100">{t.title}</h1>
                 <p className="text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wider">{t.subtitle}</p>
              </div>
           </div>

           <button 
             onClick={() => onNavigate('quiz-basics')}
             className="w-10 h-10 rounded-full bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 flex items-center justify-center text-emerald-600 dark:text-emerald-400 shadow-sm"
           >
              <Brain size={20} />
           </button>
        </div>

        {/* Search & Tabs */}
        <div className="space-y-4">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <input 
               type="text"
               placeholder={t.search}
               value={searchTerm}
               onChange={(e) => setSearchTerm(e.target.value)}
               className="w-full bg-slate-100 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl py-2.5 pl-9 pr-4 text-sm outline-none focus:ring-2 focus:ring-emerald-500/20"
            />
          </div>

          <div className="flex p-1 bg-slate-100 dark:bg-slate-950 rounded-xl">
             <button 
               onClick={() => setActiveTab('quran')}
               className={`flex-1 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'quran' ? 'bg-white dark:bg-slate-800 text-emerald-600 shadow-sm' : 'text-slate-500 dark:text-slate-400'}`}
             >
               {t.quran}
             </button>
             <button 
               onClick={() => setActiveTab('lessons')}
               className={`flex-1 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'lessons' ? 'bg-white dark:bg-slate-800 text-indigo-600 shadow-sm' : 'text-slate-500 dark:text-slate-400'}`}
             >
               {t.lessons}
             </button>
          </div>
        </div>
      </header>

      {/* Content Lists */}
      <div className="flex-1 overflow-y-auto p-4 pb-24">
         {loading ? (
             <div className="flex flex-col items-center justify-center py-20">
                 <Loader2 size={32} className="animate-spin text-emerald-500 mb-2" />
                 <p className="text-slate-400 text-sm">{t.loading}</p>
             </div>
         ) : activeTab === 'quran' ? (
             // Quran List
             <div className="space-y-3">
                 {filteredSurahs.map(surah => (
                    <button 
                      key={surah.number}
                      onClick={() => loadSurah(surah)}
                      className="w-full bg-white dark:bg-slate-900 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 flex items-center justify-between hover:border-emerald-200 dark:hover:border-emerald-800 transition-all group shadow-sm"
                    >
                        <div className="flex items-center gap-4">
                           <div className="w-10 h-10 rounded-lg bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400 flex items-center justify-center font-bold text-sm">
                              {surah.number}
                           </div>
                           <div className="text-left">
                              <h3 className="font-bold text-slate-800 dark:text-slate-100">{surah.englishName}</h3>
                              <p className="text-xs text-slate-500 dark:text-slate-400">{surah.englishNameTranslation} • {surah.numberOfAyahs} {t.verses}</p>
                           </div>
                        </div>
                        <span className="font-arabic text-lg text-emerald-600/80 dark:text-emerald-400/80 group-hover:scale-110 transition-transform">
                           {surah.name.replace('سُورَةُ ', '')}
                        </span>
                    </button>
                 ))}
             </div>
         ) : (
             // Lessons List
             <div className="grid gap-4">
                 {filteredLessons.map(lesson => (
                    <button 
                      key={lesson.id}
                      onClick={() => openLesson(lesson)}
                      className="w-full bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-100 dark:border-slate-800 flex items-center justify-between hover:border-indigo-200 dark:hover:border-indigo-800 transition-all shadow-sm group active:scale-[0.99]"
                    >
                        <div className="flex items-center gap-4">
                           <div className={`w-12 h-12 rounded-xl bg-gradient-to-br ${lesson.color} text-white flex items-center justify-center shadow-md`}>
                              {React.createElement(lesson.icon, { size: 20 })}
                           </div>
                           <div className="text-left">
                              <h3 className="font-bold text-slate-800 dark:text-slate-100 text-lg">{language === 'fr' ? lesson.title_fr : lesson.title_en}</h3>
                              <p className="text-xs text-slate-500 dark:text-slate-400 line-clamp-1">{language === 'fr' ? lesson.desc_fr : lesson.desc_en}</p>
                           </div>
                        </div>
                        <ChevronRight size={20} className="text-slate-300 dark:text-slate-600 group-hover:translate-x-1 transition-transform" />
                    </button>
                 ))}
             </div>
         )}
      </div>
    </div>
  );
};

