export const generateQuiz = async (topic: string, count: number = 3, language: string = 'en'): Promise<QuizQuestion[]> => {
  const langPrompt = language === 'fr' ? 'French' : 'English';

  // Helper to shuffle fallback
  const getFallback = () => {
    return [...FALLBACK_QUIZ_POOL]
      .sort(() => 0.5 - Math.random())
      .slice(0, count);
  };

  if (!apiKey) return getFallback();

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Generate ${count} multiple-choice quiz questions about "${topic}".
      Language: ${langPrompt}.
      Include 4 options for each question.
      Topics to cover if not specified: Pillars of Islam, Quran Surahs, Prophets Stories, Hadiths, Islamic Holidays.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              correctAnswer: { type: Type.INTEGER, description: "Index of correct option (0-3)" },
              explanation: { type: Type.STRING },
            },
            required: ["question", "options", "correctAnswer", "explanation"],
          },
        },
      },
    });
    const data = JSON.parse(response.text || '[]');
    if (!Array.isArray(data) || data.length === 0) throw new Error("Invalid format");
    return data as QuizQuestion[];
  } catch (error) {
    handleQuotaError(error, "Quiz Generation");
    return getFallback();
  }
};

export const findMosques = async (lat: number, lng: number, language: string = 'en'): Promise<{ text: string, places: PlaceResult[] }> => {
  if (!apiKey) return { text: "", places: [] };
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Find the best rated mosques nearby.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: { retrievalConfig: { latLng: { latitude: lat, longitude: lng } } }
      },
    });
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const mapPlaces = chunks.filter((c: any) => c.maps).map((c: any) => ({
      title: c.maps.title,
      uri: c.maps.uri,
      snippet: c.maps.placeAnswerSources?.reviewSnippets?.[0]?.snippet,
      type: 'mosque'
    }));
    return { text: response.text || "", places: mapPlaces };
  } catch (error) { 
    handleQuotaError(error, "Find Mosques");
    return { text: "", places: [] }; 
  }
};

