             <circle cx="14" cy="7" r="2.5" />
             {/* Body Sitting */}
             <path d="M14 10v6l3 5" />
             {/* Legs folded */}
             <path d="M14 16H8l-2 5" />
             {/* Finger raised */}
             <path d="M14 12l4 1l1-3" />
          </g>
        );

      // --- ZAKAT VISUALS ---
      case 'zakat_calc':
        return (
          <g stroke="currentColor" strokeWidth="2" fill="none" strokeLinecap="round" strokeLinejoin="round">
             <rect x="2" y="4" width="20" height="16" rx="2" />
             <line x1="6" y1="8" x2="6" y2="8" />
             <line x1="10" y1="8" x2="10" y2="8" />
             <line x1="14" y1="8" x2="14" y2="8" />
             <line x1="18" y1="8" x2="18" y2="8" />
             <line x1="2" y1="12" x2="22" y2="12" />
             <path d="M12 16v.01" strokeWidth="3" />
          </g>
        );
      case 'zakat_give':
        return (
          <g stroke="currentColor" strokeWidth="2" fill="none" strokeLinecap="round" strokeLinejoin="round">
             <circle cx="12" cy="12" r="10" />
             <path d="M16 8h-6a2 2 0 1 0 0 4h4a2 2 0 1 1 0 4H8" />
             <path d="M12 18V6" />
          </g>
        );

      // --- RAMADAN VISUALS ---
      case 'ramadan_moon':
        return (
          <g stroke="currentColor" strokeWidth="2" fill="none" strokeLinecap="round" strokeLinejoin="round">
             <path d="M12 3a6 6 0 0 0 9 9 9 9 0 1 1-9-9Z" />
          </g>
        );
      case 'ramadan_no_food':
        return (
          <g stroke="currentColor" strokeWidth="2" fill="none" strokeLinecap="round" strokeLinejoin="round">
             <circle cx="12" cy="12" r="10" />
             <line x1="4.93" y1="4.93" x2="19.07" y2="19.07" />
             <path d="M16 12a4 4 0 0 1-8 0" />
          </g>
        );

      // --- TAWAKKUL ---
      case 'tawakkul_tie':
        return (
          <g stroke="currentColor" strokeWidth="2" fill="none" strokeLinecap="round" strokeLinejoin="round">
             <path d="M10 13a5 5 0 0 0 7.54.54l3-3a5 5 0 0 0-7.07-7.07l-1.72 1.71" />
             <path d="M14 11a5 5 0 0 0-7.54-.54l-3 3a5 5 0 0 0 7.07 7.07l1.71-1.71" />
          </g>
        );
      case 'tawakkul_heart':
        return (
          <g stroke="currentColor" strokeWidth="2" fill="none" strokeLinecap="round" strokeLinejoin="round">
             <path d="M19 14c1.49-1.46 3-3.21 3-5.5A5.5 5.5 0 0 0 16.5 3c-1.76 0-3 .5-4.5 2-1.5-1.5-2.74-2-4.5-2A5.5 5.5 0 0 0 2 8.5c0 2.3 1.5 4.05 3 5.5l7 7Z" />
          </g>
        );

      default: // Generic Star
        return (
          <g stroke="currentColor" strokeWidth="2" fill="none" strokeLinecap="round" strokeLinejoin="round">
             <polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2" />
          </g>
        );
    }
  };

  return (
    <div className={`w-40 h-40 bg-white/20 dark:bg-white/5 rounded-full flex items-center justify-center mb-8 backdrop-blur-sm shadow-xl border-4 border-white/20 animate-fade-in-up`}>
       <svg viewBox="0 0 24 24" className="w-24 h-24 text-white drop-shadow-md">
          {getPath()}
       </svg>
    </div>
  );
};

