const Academy: React.FC<AcademyProps> = ({ onNavigate, language = 'en' }) => {
  // View State
  const [activeTab, setActiveTab] = useState<'quran' | 'lessons'>('quran');
  const [view, setView] = useState<'dashboard' | 'lesson_view' | 'player'>('dashboard');

  // Data State
  const [surahs, setSurahs] = useState<SurahDef[]>([]);

  // Player State (Quran & Lessons)
  const [activeModule, setActiveModule] = useState<LessonModule | null>(null);
  const [activeLesson, setActiveLesson] = useState<Lesson | null>(null);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [hideText, setHideText] = useState(false);
  const [isLooping, setIsLooping] = useState(false);

  // Quiz State
  const [quizMode, setQuizMode] = useState(false);
  const [quizQuestions, setQuizQuestions] = useState<QuizQuestion[]>([]);
  const [currentQuizIndex, setCurrentQuizIndex] = useState(0);
  const [quizScore, setQuizScore] = useState(0);
  const [quizLoading, setQuizLoading] = useState(false);
  const [showQuizResult, setShowQuizResult] = useState(false);
  const [selectedOption, setSelectedOption] = useState<number | null>(null);
  const [isAnswered, setIsAnswered] = useState(false);

  // Loading/Search State
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Translations
  const t = {
    title: language === 'fr' ? 'Académie' : 'Academy',
    subtitle: language === 'fr' ? 'Savoir Sacré' : 'Sacred Knowledge',
    quran: language === 'fr' ? 'Coran' : 'Quran',
    lessons: language === 'fr' ? 'Leçons' : 'Lessons',
    search: language === 'fr' ? 'Rechercher...' : 'Search...',
    verses: language === 'fr' ? 'versets' : 'verses',
    loading: language === 'fr' ? 'Chargement...' : 'Loading...',
    start: language === 'fr' ? 'Commencer' : 'Start',
    noAudio: language === 'fr' ? 'Audio non requis' : 'Audio not required',
    lessonComplete: language === 'fr' ? 'Leçon Terminée' : 'Lesson Complete',
    next: language === 'fr' ? 'Suivant' : 'Next',
    prev: language === 'fr' ? 'Précédent' : 'Previous',
    quizTitle: language === 'fr' ? 'Quiz Islamique' : 'Islamic Quiz',
    quizLoading: language === 'fr' ? 'Préparation de votre défi...' : 'Preparing your challenge...',
    question: language === 'fr' ? 'Question' : 'Question',
    score: language === 'fr' ? 'Score' : 'Score',
    playAgain: language === 'fr' ? 'Rejouer' : 'Play Again',
    close: language === 'fr' ? 'Fermer' : 'Close'
  };

  // --- Initial Data Fetch (Surahs) ---
  useEffect(() => {
    const fetchSurahs = async () => {
      try {
        const cached = localStorage.getItem('academy_surahs');
        if (cached) {
          setSurahs(JSON.parse(cached));
          return;
        }
        const res = await fetch('https://api.alquran.cloud/v1/surah');
        const data = await res.json();
        if (data.code === 200) {
          setSurahs(data.data);
          localStorage.setItem('academy_surahs', JSON.stringify(data.data));
        }
      } catch (e) {
        console.error("Failed to load surahs", e);
      }
    };
    fetchSurahs();
  }, []);

  // --- Audio Logic (Quran Only) ---
  useEffect(() => {
    if (activeModule?.type === 'quran' && audioRef.current && activeModule.content[currentIndex]) {
       audioRef.current.src = activeModule.content[currentIndex].audio;
       if (isPlaying) audioRef.current.play().catch(() => setIsPlaying(false));
    }
  }, [currentIndex, activeModule]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;

    const handleEnded = () => {
      if (isLooping) {
        audio.currentTime = 0;
        audio.play();
      } else {
        if (currentIndex < (activeModule?.content.length || 0) - 1) {
          setCurrentIndex(c => c + 1);
        } else {
          setIsPlaying(false);
        }
      }
    };

    audio.addEventListener('ended', handleEnded);
    return () => audio.removeEventListener('ended', handleEnded);
  }, [isLooping, currentIndex, activeModule]);

  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  // --- Quiz Logic ---
  const startQuiz = async () => {
    setQuizMode(true);
    setQuizLoading(true);
    setShowQuizResult(false);
    setCurrentQuizIndex(0);
    setQuizScore(0);
    setSelectedOption(null);
    setIsAnswered(false);

    // Requesting mixed topics: Pillars, Surahs, Prophets, Hadiths, Holidays
    const topic = language === 'fr' 
        ? "Connaissances Générales Islamiques (Piliers, Sourates Coran, Histoires des Prophètes, Hadiths, Fêtes Islamiques)" 
        : "General Islamic Knowledge (Pillars of Islam, Quran Surahs, Prophets Stories, Hadiths, Islamic Holidays)";

    const questions = await generateQuiz(topic, 10, language);
    setQuizQuestions(questions);
    setQuizLoading(false);
  };

  const handleAnswer = (index: number) => {
    if (isAnswered) return;
    setSelectedOption(index);
    setIsAnswered(true);
    if (index === quizQuestions[currentQuizIndex].correctAnswer) {
        setQuizScore(s => s + 1);
    }
  };

  const nextQuestion = () => {
    if (currentQuizIndex < quizQuestions.length - 1) {
        setCurrentQuizIndex(i => i + 1);
        setSelectedOption(null);
        setIsAnswered(false);
    } else {
        setShowQuizResult(true);
    }
  };

  const closeQuiz = () => {
      setQuizMode(false);
      setQuizQuestions([]);
  };

  // --- Loading Logic ---

  const loadSurah = async (surah: SurahDef) => {
    setLoading(true);
    try {
      const translationEdition = language === 'fr' ? 'fr.hamidullah' : 'en.sahih';

      const resText = await fetch(`https://api.alquran.cloud/v1/surah/${surah.number}/editions/quran-uthmani,${translationEdition},en.transliteration`);
      const dataText = await resText.json();

      const resAudio = await fetch(`https://api.alquran.cloud/v1/surah/${surah.number}/ar.alafasy`);
      const dataAudio = await resAudio.json();

      if (dataText.code === 200 && dataAudio.code === 200) {
        const arabicVerses = dataText.data[0].ayahs;
        const transVerses = dataText.data[1].ayahs;
        const translitVerses = dataText.data[2].ayahs;
        const audioVerses = dataAudio.data.ayahs;

        const content: Verse[] = arabicVerses.map((v: any, i: number) => ({
           verseNumber: v.numberInSurah,
           text: v.text,
           translation: transVerses[i].text,
           transliteration: translitVerses[i].text,
           audio: audioVerses[i].audio
        }));

        const module: LessonModule = {
          id: `surah_${surah.number}`,
          type: 'quran',
          title: surah.englishName,
          subtitle: surah.name,
          description: `${surah.englishNameTranslation} • ${surah.numberOfAyahs} ${t.verses}`,
          color: 'from-emerald-500 to-teal-600',
          icon: BookOpen,
          progress: 0,
          content
        };

        setActiveModule(module);
        setActiveLesson(null);
        setCurrentIndex(0);
        setView('player');
      }
    } catch (e) {
      console.error(e);
      alert(language === 'fr' ? "Erreur de chargement" : "Error loading Surah");
    } finally {
      setLoading(false);
    }
  };

  const openLesson = (lesson: Lesson) => {
    setActiveLesson(lesson);
    setActiveModule(null);
    setCurrentIndex(0);
    setView('lesson_view');
  };

  // --- Filtering ---
  const filteredSurahs = surahs.filter(s => 
    s.englishName.toLowerCase().includes(searchTerm.toLowerCase()) || 
    s.englishNameTranslation.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const filteredLessons = LESSONS_DATA.filter(l => 
    (language === 'fr' ? l.title_fr : l.title_en).toLowerCase().includes(searchTerm.toLowerCase())
  );

  // --- Render QUIZ OVERLAY ---
  if (quizMode) {
      return (
          <div className="fixed inset-0 z-50 bg-slate-50 dark:bg-slate-950 flex flex-col animate-fade-in">
              <div className="p-4 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center bg-white dark:bg-slate-900">
                  <button onClick={closeQuiz} className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800">
                      <X size={24} className="text-slate-500" />
                  </button>
                  <h2 className="font-bold text-lg text-slate-800 dark:text-slate-100">{t.quizTitle}</h2>
                  <div className="w-10"></div> {/* Spacer */}
              </div>

              {quizLoading ? (
                  <div className="flex-1 flex flex-col items-center justify-center space-y-4">
                      <Loader2 size={48} className="text-emerald-500 animate-spin" />
                      <p className="text-slate-500 dark:text-slate-400 font-medium animate-pulse">{t.quizLoading}</p>
                  </div>
              ) : showQuizResult ? (
                  <div className="flex-1 flex flex-col items-center justify-center p-6 text-center space-y-6 animate-fade-in-up">
                      <div className="w-24 h-24 bg-emerald-100 dark:bg-emerald-900/30 rounded-full flex items-center justify-center text-emerald-600 dark:text-emerald-400 mb-2">
                          <Trophy size={48} />
                      </div>
                      <h3 className="text-3xl font-bold text-slate-800 dark:text-slate-100">{t.score}: {quizScore} / {quizQuestions.length}</h3>
                      <p className="text-slate-500 dark:text-slate-400 max-w-xs">
                          {quizScore > 7 ? (language === 'fr' ? "Excellent travail ! MashaAllah." : "Excellent work! MashaAllah.") : (language === 'fr' ? "Continuez à apprendre !" : "Keep learning!")}
                      </p>

                      <div className="flex gap-4 w-full max-w-sm">
                          <button onClick={closeQuiz} className="flex-1 py-3 bg-slate-200 dark:bg-slate-800 text-slate-700 dark:text-slate-200 rounded-xl font-bold hover:bg-slate-300 dark:hover:bg-slate-700 transition-colors">
                              {t.close}
                          </button>
                          <button onClick={startQuiz} className="flex-1 py-3 bg-emerald-600 text-white rounded-xl font-bold hover:bg-emerald-700 transition-colors flex items-center justify-center gap-2">
                              <RefreshCw size={18} /> {t.playAgain}
                          </button>
                      </div>
                  </div>
              ) : (
                  <div className="flex-1 flex flex-col p-6 overflow-y-auto">
                      {/* Progress */}
                      <div className="w-full bg-slate-200 dark:bg-slate-800 h-2 rounded-full mb-6">
                          <div className="bg-emerald-500 h-2 rounded-full transition-all duration-500" style={{ width: `${((currentQuizIndex + 1) / quizQuestions.length) * 100}%` }}></div>
                      </div>

                      <div className="flex-1">
                          <span className="text-xs font-bold text-emerald-600 dark:text-emerald-400 uppercase tracking-wider mb-2 block">
                              {t.question} {currentQuizIndex + 1} / {quizQuestions.length}
                          </span>
                          <h3 className="text-xl font-bold text-slate-800 dark:text-slate-100 leading-snug mb-8">
                              {quizQuestions[currentQuizIndex].question}
                          </h3>

                          <div className="space-y-3">
                              {quizQuestions[currentQuizIndex].options.map((option, idx) => {
                                  let btnClass = "bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 text-slate-700 dark:text-slate-300 hover:border-emerald-500 dark:hover:border-emerald-500";

                                  if (isAnswered) {
                                      if (idx === quizQuestions[currentQuizIndex].correctAnswer) {
                                          btnClass = "bg-emerald-100 dark:bg-emerald-900/30 border-emerald-500 text-emerald-800 dark:text-emerald-200";
                                      } else if (idx === selectedOption) {
                                          btnClass = "bg-red-100 dark:bg-red-900/30 border-red-500 text-red-800 dark:text-red-200";
                                      } else {
                                          btnClass = "opacity-50 border-transparent bg-slate-50 dark:bg-slate-900";
                                      }
                                  }

                                  return (
                                      <button
                                          key={idx}
                                          onClick={() => handleAnswer(idx)}
                                          disabled={isAnswered}
                                          className={`w-full p-4 rounded-xl border-2 text-left transition-all font-medium ${btnClass}`}
                                      >
                                          {option}
                                      </button>
                                  );
                              })}
                          </div>

                          {isAnswered && (
                              <div className="mt-6 p-4 bg-blue-50 dark:bg-blue-900/20 rounded-xl border border-blue-100 dark:border-blue-900/30 animate-fade-in-up">
                                  <div className="flex gap-2">
                                      <Quote className="text-blue-500 flex-shrink-0" size={20} />
                                      <p className="text-sm text-blue-800 dark:text-blue-200 leading-relaxed">
                                          {quizQuestions[currentQuizIndex].explanation}
                                      </p>
                                  </div>
                              </div>
                          )}
                      </div>

                      <div className="mt-6">
                          <button 
                              onClick={nextQuestion}
                              disabled={!isAnswered}
                              className="w-full py-4 bg-emerald-600 disabled:bg-slate-300 dark:disabled:bg-slate-800 text-white rounded-xl font-bold transition-colors flex items-center justify-center gap-2"
                          >
                              {currentQuizIndex === quizQuestions.length - 1 ? (language === 'fr' ? "Voir les résultats" : "See Results") : t.next} <ChevronRight size={20} />
                          </button>
                      </div>
                  </div>
              )}
          </div>
      );
  }

  // --- Render Quran Player ---
  if (view === 'player' && activeModule) {
    const currentItem = activeModule.content[currentIndex];
    const progressPercent = ((currentIndex + 1) / activeModule.content.length) * 100;

    return (
      <div className="h-full flex flex-col bg-slate-900 animate-fade-in relative overflow-hidden">
        <audio ref={audioRef} />

        {/* Background & Decor */}
        <div className={`absolute top-0 inset-x-0 h-[60%] bg-gradient-to-b ${activeModule.color} opacity-20 pointer-events-none`}></div>
        <div className="absolute top-0 right-0 w-64 h-64 bg-emerald-500 rounded-full mix-blend-multiply filter blur-3xl opacity-10 animate-pulse-slow"></div>

        {/* Header */}
        <div className="relative z-10 p-6 flex items-center justify-between">
           <button 
             onClick={() => {
                setIsPlaying(false);
                setView('dashboard');
