             <path d="M12 21.35l-1.45-1.32C5.4 15.36 2 12.28 2 8.5 2 5.42 4.42 3 7.5 3c1.74 0 3.41.81 4.5 2.09C13.09 3.81 14.76 3 16.5 3 19.58 3 22 5.42 22 8.5c0 3.78-3.4 6.86-8.55 11.54L12 21.35z"/>
          </g>
        );

      default: 
        return (
          <g fill="currentColor">
             <circle cx="12" cy="12" r="10" opacity="0.2"/>
             <path d="M12 2L15 8L22 9L17 14L18 21L12 17L6 21L7 14L2 9L9 8L12 2Z" />
          </g>
        );
    }
  };

  return (
    <div className={`w-48 h-48 bg-white/20 dark:bg-white/5 rounded-full flex items-center justify-center mb-8 backdrop-blur-sm shadow-2xl border-8 border-white/10 animate-fade-in-up`}>
       <svg viewBox="0 0 24 24" className="w-28 h-28 text-white drop-shadow-lg">
          {getPath()}
       </svg>
    </div>
  );
};

