interface NavigationProps {
  activeTab: string;
  setActiveTab: (tab: string) => void;
  language?: string;
  isTransparent?: boolean;
}

const TRANSLATIONS = {
  en: { home: 'Home', quran: 'Quran', prayer: 'Prayer', chat: 'Ask AI', academy: 'Academy' },
  fr: { home: 'Accueil', quran: 'Coran', prayer: 'Prière', chat: 'IA', academy: 'Académie' }
};

// Custom Icon for Man Bowing in Prayer (Ruku/Sujud representation)
const PrayerIcon = ({ size, className }: { size: number; className?: string }) => (
  <svg 
    width={size} 
    height={size} 
    viewBox="0 0 24 24" 
    fill="none" 
    stroke="currentColor" 
    strokeWidth="2" 
    strokeLinecap="round" 
    strokeLinejoin="round" 
    className={className}
  >
     {/* Abstract representation of a person bowing */}
     <circle cx="17" cy="5" r="2" />
     <path d="M19 12v7" />
     <path d="M15 11l3 1-2 7" /> 
     <path d="M12 21h7" /> 
     <path d="M4 21h3l2-4 3-4h3l1-2" />
  </svg>
);

const Navigation: React.FC<NavigationProps> = ({ activeTab, setActiveTab, language = 'en', isTransparent = false }) => {
  const t = TRANSLATIONS[language as keyof typeof TRANSLATIONS] || TRANSLATIONS.en;

  const navItems = [
    { id: 'home', icon: Home, label: t.home },
    { id: 'quran', icon: BookOpen, label: t.quran },
    { id: 'prayer-catalog', icon: PrayerIcon, label: t.prayer },
    { id: 'academy', icon: GraduationCap, label: t.academy },
    { id: 'chat', icon: MessageCircle, label: t.chat },
  ];

  return (
    <div className="fixed bottom-0 left-0 right-0 z-50 pointer-events-none flex justify-center pb-safe pt-2 px-4 transition-all duration-300">
      <nav 
        className={`pointer-events-auto transition-all duration-500 p-2 mb-4 w-full max-w-sm rounded-full flex justify-between items-center ${
          isTransparent
            ? 'bg-white/70 dark:bg-slate-900/70 backdrop-blur-md border border-white/20 dark:border-slate-800/30 shadow-lg'
            : 'bg-white/90 dark:bg-slate-900/90 backdrop-blur-xl border border-slate-200/50 dark:border-slate-800/50 shadow-[0_8px_30px_rgb(0,0,0,0.12)] dark:shadow-black/50'
        }`}
      >
        {navItems.map((item) => {
          const Icon = item.icon;
          const isActive = activeTab === item.id;
          return (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`relative flex flex-col items-center justify-center w-12 h-12 rounded-full transition-all duration-300 group ${
                isActive 
                  ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/30' 
                  : 'text-slate-400 dark:text-slate-500 hover:text-slate-600 dark:hover:text-slate-300 hover:bg-black/5 dark:hover:bg-white/5'
              }`}
            >
              <Icon size={20} className={`transition-transform duration-300 ${isActive ? 'scale-110' : ''}`} />
              {isActive && (
                <span className="absolute -bottom-8 bg-slate-800 dark:bg-slate-700 text-white text-[10px] py-1 px-2 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
                  {item.label}
                </span>
              )}
            </button>
          );
        })}
      </nav>
    </div>
  );
};

