      { arabic: "الطُّهُورُ شَطْرُ الإِيمَانِ", text: "La pureté est la moitié de la foi.", source: "Muslim" },
      { arabic: "لَوْلاَ أَنْ أَشُقَّ عَلَى أُمَّتِي لأَمَرْتُهُمْ بِالسِّوَاكِ", text: "Si je ne craignais de surcharger ma communauté, j'aurais ordonné le Siwak.", source: "Bukhari" },
      { arabic: "الْفِطْرَةُ خَمْسٌ: الْخِتَانُ وَالِاسْتِحْدَادُ...", text: "La Fitra est cinq : circoncision, rasage du pubis, coupe des ongles...", source: "Bukhari" },
      { arabic: "تَخَلَّلُوا فَإِنَّهُ نَظَافَةٌ", text: "Utilisez le cure-dent, c'est une propreté.", source: "Tabarani" },
      { arabic: "قُصُّوا الشَّوَارِبَ وَأَعْفُوا اللِّحَى", text: "Taillez les moustaches et laissez pousser les barbes.", source: "Muslim" },
      { arabic: "مَنْ أَكَلَ ثُومًا أَوْ بَصَلًا فَلْيَعْتَزِلْنَا", text: "Celui qui mange de l'ail ou de l'oignon, qu'il s'éloigne de nous (mosquée).", source: "Bukhari" },
      { arabic: "إِذَا عَطَسَ أَحَدُكُمْ فَلْيَقُلْ الْحَمْدُ لِلَّهِ", text: "Si l'un de vous éternue, qu'il dise Al-Hamdulillah.", source: "Bukhari" },
      { arabic: "إِذَا تَثَاءَبَ أَحَدُكُمْ فَلْيَكْظِمْ مَا اسْتَطَاعَ", text: "Si l'un de vous bâille, qu'il retienne autant que possible.", source: "Muslim" },
      { arabic: "غَطُّوا الْإِنَاءَ وَأَوْكُوا السِّقَاءَ", text: "Couvrez les récipients et fermez les outres.", source: "Muslim" },
      { arabic: "لَا يَبُولَنَّ أَحَدُكُمْ فِي الْمَاءِ الدَّائِمِ", text: "Qu'aucun de vous n'urine dans l'eau stagnante.", source: "Bukhari" },
      { arabic: "اتَّقُوا الْمَلَاعِنَ الثَّلَاثَ: الْبَرَازَ فِي الْمَوَارِدِ...", text: "Évitez les trois malédictions : faire ses besoins dans les points d'eau, sur la route...", source: "Abu Dawud" },
      { arabic: "إِذَا اسْتَيْقَظَ أَحَدُكُمْ مِنْ نَوْمِهِ فَلَا يَغْمِسْ يَدَهُ فِي الْإِنَاءِ", text: "Au réveil, ne plongez pas la main dans le récipient avant de l'avoir lavée.", source: "Muslim" },
      { arabic: "مَا مَلَأَ آدَمِيٌّ وِعَاءً شَرًّا مِنْ بَطْنٍ", text: "L'homme ne remplit pas de pire récipient que son ventre.", source: "Tirmidhi" },
      { arabic: "ثُلُثٌ لِطَعَامِهِ وَثُلُثٌ لِشَرَابِهِ وَثُلُثٌ لِنَفَسِهِ", text: "Un tiers pour la nourriture, un tiers pour la boisson, un tiers pour le souffle.", source: "Ibn Majah" },
      { arabic: "سَمِّ اللَّهَ وَكُلْ بِيَمِينِكَ", text: "Dis Bismillah et mange de la main droite.", source: "Bukhari" },
      { arabic: "لَا يَأْكُلَنَّ أَحَدُكُمْ بِشِمَالِهِ", text: "Que personne ne mange de la main gauche.", source: "Muslim" },
      { arabic: "لَا تَشْرَبُوا وَاحِدًا كَشُرْبِ الْبَعِيرِ", text: "Ne buvez pas d'un trait comme le chameau.", source: "Tirmidhi" },
      { arabic: "كَانَ يَتَنَفَّسُ فِي الشَّرَابِ ثَلَاثًا", text: "Le Prophète respirait trois fois en buvant (en dehors du récipient).", source: "Muslim" },
      { arabic: "إِذَا وَقَعَ الذُّبَابُ فِي شَرَابِ أَحَدِكُمْ فَلْيَغْمِسْهُ", text: "Si une mouche tombe dans votre boisson, plongez-la (puis jetez-la).", source: "Bukhari" },
      { arabic: "الْأَيْمَنَ فَالْأَيْمَنَ", text: "(Servez) celui de droite, puis celui de droite.", source: "Bukhari" },
      { arabic: "كُلُوا الزَّيْتَ وَادَّهِنُوا بِهِ", text: "Mangez de l'huile (d'olive) et enduisez-vous-en.", source: "Tirmidhi" },
      { arabic: "الْحَبَّةُ السَّوْدَاءُ شِفَاءٌ مِنْ كُلِّ دَاءٍ", text: "La graine noire est un remède contre tout mal sauf la mort.", source: "Bukhari" },
      { arabic: "الْعَسَلُ فِيهِ شِفَاءٌ لِلنَّاسِ", text: "Le miel contient une guérison pour les gens.", source: "Bukhari" },
      { arabic: "الْكَمْأَةُ مِنَ الْمَنِّ وَمَاؤُهَا شِفَاءٌ لِلْعَيْنِ", text: "La truffe est de la manne et son eau est une guérison pour l'œil.", source: "Bukhari" },
      { arabic: "نَهَى عَنِ النَّفْخِ فِي الشَّرَابِ", text: "Il a interdit de souffler dans la boisson.", source: "Abu Dawud" },
      { arabic: "لَا يَمْشِ أَحَدُكُمْ فِي نَعْلٍ وَاحِدَةٍ", text: "Que personne ne marche avec une seule chaussure.", source: "Bukhari" },
      { arabic: "إِنَّ اللَّهَ جَمِيلٌ يُحِبُّ الْجَمَالَ", text: "Allah est Beau et aime la beauté.", source: "Muslim" },
      { arabic: "الْبَسُوا مِنْ ثِيَابِكُمُ الْبَيَاضَ", text: "Portez des vêtements blancs.", source: "Tirmidhi" },
      { arabic: "حُرِّمَ لِبَاسُ الْحَرِيرِ وَالذَّهَبِ عَلَى ذُكُورِ أُمَّتِي", text: "La soie et l'or sont interdits aux hommes de ma communauté.", source: "Tirmidhi" },
      { arabic: "خَالِفُوا الْمُشْرِكِينَ وَفِّرُوا اللِّحَى", text: "Distinguez-vous des polythéistes, laissez pousser la barbe.", source: "Bukhari" },
      { arabic: "مَنْ جَرَّ ثَوْبَهُ خُيَلَاءَ لَمْ يَنْظُرِ اللَّهُ إِلَيْهِ", text: "Celui qui traîne son vêtement par orgueil, Allah ne le regarde pas.", source: "Bukhari" },
      { arabic: "لَعَنَ اللَّهُ الْمُتَشَبِّهِينَ مِنَ الرِّجَالِ بِالنِّسَاءِ", text: "Allah maudit les hommes qui imitent les femmes.", source: "Bukhari" },
      { arabic: "إِذَا انْتَعَلَ أَحَدُكُمْ فَلْيَبْدَأْ بِالْيُمْنَى", text: "Si vous vous chaussez, commencez par la droite.", source: "Bukhari" },
      { arabic: "أَطْيَبُ الطِّيبِ الْمِسْكُ", text: "Le meilleur parfum est le musc.", source: "Muslim" },
      { arabic: "تَدَاوَوْا فَإِنَّ اللَّهَ لَمْ يَضَعْ دَاءً إِلَّا وَضَعَ لَهُ شِفَاءً", text: "Soignez-vous, car Allah n'a pas mis de maladie sans remède.", source: "Abu Dawud" },
      { arabic: "الْحُمَّى مِنْ فَيْحِ جَهَنَّمَ فَأَبْرِدُوهَا بِالْمَاءِ", text: "La fièvre est une bouffée de l'Enfer, refroidissez-la avec de l'eau.", source: "Bukhari" },
      { arabic: "نَهَى أَنْ يَتَخَلَّى الرَّجُلُ فِي طَرِيقِ النَّاسِ", text: "Il a interdit de faire ses besoins sur le chemin des gens.", source: "Muslim" },
      { arabic: "إِذَا بَالَ أَحَدُكُمْ فَلَا يَأْخُذَنَّ ذَكَرَهُ بِيَمِينِهِ", text: "Si vous urinez, ne tenez pas votre sexe de la main droite.", source: "Bukhari" },
      { arabic: "الْوُضُوءُ قَبْلَ الطَّعَامِ وَبَعْدَهُ", text: "Les ablutions (lavage des mains) avant et après le repas (sont recommandées).", source: "Tirmidhi" },
      { arabic: "طَهِّرُوا أَفْنِيَتَكُمْ", text: "Nettoyez vos parvis.", source: "Tirmidhi" },
      { arabic: "بَارَكَ اللَّهُ لِأُمَّتِي فِي بُكُورِهَا", text: "Allah a béni ma communauté dans son matin (tôt).", source: "Tirmidhi" },
      { arabic: "نَوْمُ الصُّبْحَةِ يَمْنَعُ الرِّزْقَ", text: "Dormir le matin (après Fajr) empêche la subsistance.", source: "Ahmed" },
      { arabic: "مَنْ أَكْرَمَ شَعْرَهُ فَلْيُكْرِمْهُ", text: "Celui qui a des cheveux, qu'il les honore (les entretienne).", source: "Abu Dawud" },
      { arabic: "إِنَّ اللَّهَ طَيِّبٌ يُحِبُّ الطَّيِّبَ نَظِيفٌ يُحِبُّ النَّظَافَةَ", text: "Allah est Bon, Il aime la bonté ; Propre, Il aime la propreté.", source: "Tirmidhi" }
    ]
  },
  {
    id: 'ahlulbayt',
    title: "Ahl-ul-Bayt & Mérites",
    icon: Shield,
    description: "Les mérites de la famille du Prophète, Ali, Fatima, Hassan et Hussain",
    hadiths: [
      { arabic: "تَرَكْتُ فِيكُمْ مَا إِنْ تَمَسَّكْتُمْ بِهِ لَنْ تَضِلُّوا: كِتَابَ اللَّهِ وَعِتْرَتِي", text: "Je laisse parmi vous deux choses : le Livre d'Allah et ma famille (Itrah).", source: "Tirmidhi" },
      { arabic: "أُذَكِّرُكُمُ اللَّهَ فِي أَهْلِ بَيْتِي", text: "Je vous rappelle Allah concernant les gens de ma maison.", source: "Muslim" },
      { arabic: "فَاطِمَةُ بَضْعَةٌ مِنِّي", text: "Fatima est une partie de moi.", source: "Bukhari" },
      { arabic: "فَاطِمَةُ سَيِّدَةُ نِسَاءِ أَهْلِ الْجَنَّةِ", text: "Fatima est la maîtresse des femmes du Paradis.", source: "Bukhari" },
      { arabic: "عَلِيٌّ مِنِّي وَأَنَا مِنْ عَلِيٍّ", text: "Ali est de moi et je suis d'Ali.", source: "Tirmidhi" },
      { arabic: "أَنْتَ مِنِّي بِمَنْزِلَةِ هَارُونَ مِنْ مُوسَى", text: "Tu es pour moi ce que Aaron était pour Moïse.", source: "Bukhari & Muslim" },
      { arabic: "مَنْ كُنْتُ مَوْلَاهُ فَعَلِيٌّ مَوْلَاهُ", text: "Celui dont je suis le Maître, Ali est son Maître.", source: "Tirmidhi" },
      { arabic: "لَا يُحِبُّ عَلِيًّا إِلَّا مُؤْمِنٌ وَلَا يُبْغِضُهُ إِلَّا مُنَافِقٌ", text: "Nul n'aime Ali sauf un croyant, nul ne le déteste sauf un hypocrite.", source: "Muslim" },
      { arabic: "أَنَا مَدِينَةُ الْعِلْمِ وَعَلِيٌّ بَابُهَا", text: "Je suis la cité du savoir et Ali en est la porte.", source: "Tirmidhi (Hasan)" },
      { arabic: "الْحَسَنُ وَالْحُسَيْنُ سَيِّدَا شَبَابِ أَهْلِ الْجَنَّةِ", text: "Hasan et Husayn sont les maîtres des jeunes du Paradis.", source: "Tirmidhi" },
      { arabic: "حُسَيْنٌ مِنِّي وَأَنَا مِنْ حُسَيْنٍ", text: "Husayn est de moi et je suis de Husayn.", source: "Tirmidhi" },
      { arabic: "أَحَبَّ اللَّهُ مَنْ أَحَبَّ حُسَيْنًا", text: "Allah aime celui qui aime Husayn.", source: "Tirmidhi" },
      { arabic: "هُمَا رَيْحَانَتَايَ مِنَ الدُّنْيَا", text: "Ils (Hasan et Husayn) sont mes deux basilics de ce monde.", source: "Bukhari" },
      { arabic: "اللَّهُمَّ إِنِّي أُحِبُّهُمَا فَأَحِبَّهُمَا", text: "Ô Allah je les aime, alors aime-les.", source: "Bukhari" },
      { arabic: "الْمَهْدِيُّ مِنَّا أَهْلَ الْبَيْتِ", text: "Le Mahdi est de nous, les Ahl-ul-Bayt.", source: "Ibn Majah" },
      { arabic: "الْمَهْدِيُّ مِنْ وَلَدِ فَاطِمَةَ", text: "Le Mahdi est de la descendance de Fatima.", source: "Abu Dawud" },
      { arabic: "يُصْلِحُهُ اللَّهُ فِي لَيْلَةٍ", text: "Allah le (le Mahdi) rectifiera en une nuit.", source: "Ibn Majah" },
      { arabic: "إِنَّمَا يُرِيدُ اللَّهُ لِيُذْهِبَ عَنْكُمُ الرِّجْسَ أَهْلَ الْبَيْتِ", text: "Allah ne veut qu'éloigner de vous la souillure, ô Gens de la Maison.", source: "Coran (Ahzab)" },
      { arabic: "اللَّهُمَّ هَؤُلَاءِ أَهْلُ بَيْتِي", text: "Ô Allah, ceux-ci sont les gens de ma maison (sous le Manteau).", source: "Muslim" },
      { arabic: "مَثَلُ أَهْلِ بَيْتِي مَثَلُ سَفِينَةِ نُوحٍ", text: "L'exemple de ma famille est comme l'Arche de Noé.", source: "Tabarani" },
      { arabic: "النُّجُومُ أَمَانٌ لِأَهْلِ السَّمَاءِ وَأَهْلُ بَيْتِي أَمَانٌ لِأُمَّتِي", text: "Les étoiles sont une sécurité pour le ciel, et ma famille est une sécurité pour ma communauté.", source: "Mustadrak" },
      { arabic: "خَيْرُكُمْ خَيْرُكُمْ لِأَهْلِي", text: "Le meilleur d'entre vous est le meilleur pour ma famille.", source: "Tirmidhi" },
      { arabic: "أَرْبَعَةٌ أَنَا لَهُمْ شَفِيعٌ... وَالْمُكْرِمُ لِذُرِّيَّتِي", text: "Quatre personnes pour qui j'intercèderai... dont celui qui honore ma descendance.", source: "Kanz al-Ummal" },
      { arabic: "لَا تَقُومُ السَّاعَةُ حَتَّى يَمْلِكَ رَجُلٌ مِنْ أَهْلِ بَيْتِي", text: "L'Heure ne viendra pas avant qu'un homme de ma famille ne règne.", source: "Ahmed" },
      { arabic: "لِكُلِّ نَبِيٍّ عَصَبَةٌ... إِلَّا وَلَدَ فَاطِمَةَ فَأَنَا وَلِيُّهُمْ", text: "Tout prophète a une lignée... sauf les enfants de Fatima, je suis leur tuteur.", source: "Tabarani" },
      { arabic: "وَأَحِبُّوا أَهْلَ بَيْتِي لِحُبِّي", text: "Aimez ma famille par amour pour moi.", source: "Tirmidhi" },
      { arabic: "مَنْ آَذَى عَلِيًّا فَقَدْ آذَانِي", text: "Celui qui fait du mal à Ali m'a fait du mal.", source: "Ahmed" },
      { arabic: "اللَّهُمَّ وَالِ مَنْ وَالَاهُ وَعَادِ مَنْ عَادَاهُ", text: "Ô Allah, allie-Toi à celui qui s'allie à lui (Ali) et sois l'ennemi de son ennemi.", source: "Tirmidhi" },
      { arabic: "عَلِيٌّ مَعَ الْقُرْآنِ وَالْقُرْآنُ مَعَ عَلِيٍّ", text: "Ali est avec le Coran et le Coran est avec Ali.", source: "Tabarani" },
      { arabic: "السَّلَامُ عَلَى آلِ يَاسِينَ", text: "Paix sur la famille de Yasin (Muhammad).", source: "Coran / Tafsir" },
      { arabic: "لَا أَسْأَلُكُمْ عَلَيْهِ أَجْرًا إِلَّا الْمَوَدَّةَ فِي الْقُرْبَى", text: "Je ne vous demande pas de salaire si ce n'est l'affection pour les proches.", source: "Coran (Shura)" },
      { arabic: "نَحْنُ أَهْلُ بَيْتٍ لَا يُقَاسُ بِنَا أَحَدٌ", text: "Nous sommes les Ahl-ul-Bayt, personne ne peut nous être comparé.", source: "Daylami" },
      { arabic: "إِنَّ ابْنِي هَذَا سَيِّدٌ (الحسن)", text: "Mon fils que voici (Hasan) est un Sayyid (maître).", source: "Bukhari" },
      { arabic: "وَلَعَلَّ اللَّهَ أَنْ يُصْلِحَ بِهِ بَيْنَ فِئَتَيْنِ مِنَ الْمُسْلِمِينَ", text: "Peut-être qu'Allah réconciliera par lui deux groupes de musulmans.", source: "Bukhari" },
      { arabic: "أَوَّلُ مَنْ يَدْخُلُ عَلَيَّ الْجَنَّةَ فَاطِمَةُ", text: "La première à entrer au Paradis après moi est Fatima.", source: "Hakim" },
      { arabic: "يَا فَاطِمَةُ أَلَا تَرْضَيْنَ أَنْ تَكُونِي سَيِّدَةَ نِسَاءِ الْمُؤْمِنِينَ", text: "Ô Fatima, n'es-tu pas satisfaite d'être la maîtresse des croyantes ?", source: "Bukhari" },
      { arabic: "إِنَّمَا سُمِّيَتْ فَاطِمَةَ لِأَنَّ اللَّهَ فَطَمَهَا وَمُحِبِّيهَا عَنِ النَّارِ", text: "Elle a été nommée Fatima car Allah l'a sevrée (protégée) elle et ceux qui l'aiment du Feu.", source: "Daylami" },
      { arabic: "الشَّقَاوَةُ كُلُّ الشَّقَاوَةِ لِمَنْ أَبْغَضَنَا", text: "Le malheur total est pour celui qui nous déteste.", source: "Tabarani" },
      { arabic: "مَنْ مَاتَ عَلَى حُبِّ آلِ مُحَمَّدٍ مَاتَ شَهِيدًا", text: "Celui qui meurt avec l'amour de la famille de Muhammad meurt martyr.", source: "Tafsir Kashshaf" },
      { arabic: "لِكُلِّ شَيْءٍ أَسَاسٌ وَأَسَاسُ الْإِسْلَامِ حُبُّنَا أَهْلَ الْبَيْتِ", text: "Toute chose a une base, et la base de l'Islam est notre amour.", source: "Kanz" },
      { arabic: "الصَّلَاةُ عَلَيْنَا تَمْحَقُ الذُّنُوبَ", text: "La prière sur nous efface les péchés comme l'eau éteint le feu.", source: "Daylami" },
