        setCurrentQuizIndex(i => i + 1);
        setSelectedOption(null);
        setIsAnswered(false);
    } else {
        setShowQuizResult(true);
    }
  };

  const closeQuiz = () => {
      setQuizMode(false);
      setQuizQuestions([]);
