         <button onClick={onBack} className="absolute top-6 left-6 p-2 bg-slate-100 dark:bg-slate-800 rounded-full hover:scale-105 transition-transform">
            <ChevronRight size={20} className="rotate-180 text-slate-600 dark:text-slate-300" />
         </button>

         <div className="flex flex-col items-center">
            <div className="w-24 h-24 rounded-full bg-gradient-to-tr from-emerald-400 to-teal-600 p-1 mb-4 shadow-lg shadow-emerald-500/20 relative group cursor-pointer">
               <div className="w-full h-full rounded-full bg-white dark:bg-slate-800 flex items-center justify-center overflow-hidden">
                  <User size={40} className="text-slate-300" />
               </div>
               <div className="absolute bottom-0 right-0 bg-white dark:bg-slate-700 p-1.5 rounded-full shadow-sm border border-slate-100 dark:border-slate-600">
                  <Camera size={14} className="text-slate-500 dark:text-slate-300" />
               </div>
            </div>

            {isEditing ? (
              <div className="flex items-center gap-2 mb-2">
                <input 
                  type="text" 
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="bg-slate-100 dark:bg-slate-800 border-none rounded-lg px-3 py-1 text-center font-bold text-lg text-slate-800 dark:text-slate-100 outline-none focus:ring-2 focus:ring-emerald-500"
                  autoFocus
                />
                <button onClick={handleSaveProfile} className="p-1.5 bg-emerald-500 text-white rounded-full">
                  <CheckIcon size={16} />
                </button>
              </div>
            ) : (
              <h2 className="text-2xl font-bold text-slate-800 dark:text-slate-100 mb-1 flex items-center gap-2">
                {name} 
