export const generateDailyVerse = async (language: string = 'en'): Promise<DailyVerse | null> => {
  if (!apiKey) return FALLBACK_VERSES[Math.floor(Math.random() * FALLBACK_VERSES.length)];

  const langPrompt = language === 'fr' ? 'French' : 'English';
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Generate a beautiful Quranic verse for today. Include Arabic text, ${langPrompt} translation, reference, and reflection.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            arabic: { type: Type.STRING },
            translation: { type: Type.STRING },
            reference: { type: Type.STRING },
            reflection: { type: Type.STRING },
          },
          required: ["arabic", "translation", "reference", "reflection"],
        },
      },
    });

    if (!response.text) {
      throw new Error("Model returned empty text");
    }

    const data = JSON.parse(response.text);
    if (!data.arabic || !data.translation) throw new Error("Invalid response structure");
    return data as DailyVerse;
  } catch (error) { 
    handleQuotaError(error, "Daily Verse");
    return FALLBACK_VERSES[Math.floor(Math.random() * FALLBACK_VERSES.length)];
  }
};

