// --- Helper for Quota Errors ---
const handleQuotaError = (error: any, context: string) => {
  if (error.message?.includes('429') || error.message?.includes('quota') || error.status === 429) {
    console.warn(`Gemini API Quota Exceeded for ${context}. Switching to offline fallback content.`);
  } else {
    console.error(`${context} Error (Using Fallback):`, error);
  }
};

