      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            status: { type: Type.STRING, enum: ['halal', 'haram', 'doubtful'] },
            reason: { type: Type.STRING },
            concerns: { type: Type.ARRAY, items: { type: Type.STRING } },
          },
          required: ["status", "reason", "concerns"],
        },
      },
    });

    if (!response.text) return null;

    const data = cleanAndParseJSON(response.text);
    if (!data.status) return null;
    return data as HalalCheckResult;
  } catch (error) {
    handleQuotaError(error, "Halal Scan");
    return null;
  }
};

export const identifyQuranVerse = async (text: string): Promise<{ surah: number, ayah: number } | null> => {
  if (!apiKey) return null;
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Identify the specific Quranic verse (Ayah) from this text (which might be an imperfect recitation or search query): "${text}". 
      Return the Surah number and Ayah number. If not found, return null values.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            surah: { type: Type.INTEGER },
            ayah: { type: Type.INTEGER },
          },
          required: ["surah", "ayah"],
        },
      },
    });

    if (!response.text) return null;

    const data = cleanAndParseJSON(response.text);
    if (!data.surah || !data.ayah) return null;
    return data as { surah: number, ayah: number };
  } catch (error) {
    handleQuotaError(error, "Identify Verse");
    return null;
  }
};

