      { arabic: "مَا مِنْ شَيْءٍ أَثْقَلُ فِي مِيزَانِ الْمُؤْمِنِ يَوْمَ الْقِيَامَةِ مِنْ حُسْنِ الْخُلُقِ", text: "Rien n'est plus lourd dans la balance du croyant que le bon comportement.", source: "Tirmidhi" },
      { arabic: "أَكْمَلُ الْمُؤْمِنِينَ إِيمَانًا أَحْسَنُهُمْ خُلُقًا", text: "Le croyant à la foi la plus parfaite est celui qui a le meilleur caractère.", source: "Tirmidhi" },
      { arabic: "الْبِرُّ حُسْنُ الْخُلُقِ", text: "La piété, c'est le bon comportement.", source: "Muslim" },
      { arabic: "لَا تَغْضَبْ وَلَكَ الْجَنَّةُ", text: "Ne te mets pas en colère et tu auras le Paradis.", source: "Tabarani" },
      { arabic: "لَيْسَ الشَّدِيدُ بِالصُّرَعَةِ إِنَّمَا الشَّدِيدُ الَّذِي يَمْلِكُ نَفْسَهُ عِنْدَ الْغَضَبِ", text: "Le fort n'est pas celui qui terrasse, mais celui qui se maîtrise dans la colère.", source: "Bukhari" },
      { arabic: "إِنَّ الصِّدْقَ يَهْدِي إِلَى الْبِرِّ وَإِنَّ الْبِرَّ يَهْدِي إِلَى الْجَنَّةِ", text: "La véracité mène à la piété, et la piété mène au Paradis.", source: "Bukhari" },
      { arabic: "وَيْلٌ لِلَّذِي يُحَدِّثُ فَيَكْذِبُ لِيُضْحِكَ بِهِ الْقَوْمَ", text: "Malheur à celui qui ment pour faire rire les gens.", source: "Abu Dawud" },
      { arabic: "لَا يُؤْمِنُ أَحَدُكُمْ حَتَّى يُحِبَّ لِأَخِيهِ مَا يُحِبُّ لِنَفْسِهِ", text: "Nul ne croit vraiment tant qu'il n'aime pas pour son frère ce qu'il aime pour lui-même.", source: "Bukhari" },
      { arabic: "مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَصْمُتْ", text: "Que celui qui croit en Allah dise du bien ou se taise.", source: "Bukhari" },
      { arabic: "الْمُسْلِمُ مَنْ سَلِمَ الْمُسْلِمُونَ مِنْ لِسَانِهِ وَيَدِهِ", text: "Le vrai musulman est celui dont les musulmans sont à l'abri de sa langue et de sa main.", source: "Bukhari" },
      { arabic: "لَا يَدْخُلُ الْجَنَّةَ نَمَّامٌ", text: "N'entre pas au Paradis le rapporteur de calomnies.", source: "Muslim" },
      { arabic: "إِيَّاكُمْ وَالظَّنَّ فَإِنَّ الظَّنَّ أَكْذَبُ الْحَدِيثِ", text: "Méfiez-vous du soupçon, car le soupçon est la plus mensongère des paroles.", source: "Bukhari" },
      { arabic: "مَنْ لَا يَرْحَمْ لَا يُرْحَمْ", text: "Celui qui ne fait pas miséricorde ne reçoit pas miséricorde.", source: "Bukhari" },
      { arabic: "الرَّاحِمُونَ يَرْحَمُهُمُ الرَّحْمَنُ", text: "Ceux qui sont miséricordieux, le Tout-Miséricordieux leur fait miséricorde.", source: "Tirmidhi" },
      { arabic: "مَنْ تَوَاضَعَ لِلَّهِ رَفَعَهُ اللَّهُ", text: "Celui qui s'humilie pour Allah, Allah l'élève.", source: "Muslim" },
      { arabic: "لَا يَدْخُلُ الْجَنَّةَ مَنْ كَانَ فِي قَلْبِهِ مِثْقَالُ ذَرَّةٍ مِنْ كِبْرٍ", text: "N'entre pas au Paradis celui qui a un atome d'orgueil dans le cœur.", source: "Muslim" },
      { arabic: "إِنَّ اللَّهَ جَمِيلٌ يُحِبُّ الْجَمَالَ", text: "Allah est Beau et Il aime la beauté (et l'élégance morale).", source: "Muslim" },
      { arabic: "الْحَيَاءُ شُعْبَةٌ مِنَ الْإِيمَانِ", text: "La pudeur est une branche de la foi.", source: "Bukhari" },
      { arabic: "إِنَّ لِكُلِّ دِينٍ خُلُقًا وَخُلُقُ الْإِسْلَامِ الْحَيَاءُ", text: "Chaque religion a un caractère, et le caractère de l'Islam est la pudeur.", source: "Ibn Majah" },
      { arabic: "آيَةُ الْمُنَافِقِ ثَلَاثٌ: إِذَا حَدَّثَ كَذَبَ...", text: "Les signes de l'hypocrite sont trois : quand il parle il ment...", source: "Bukhari" },
      { arabic: "أَدِّ الْأَمَانَةَ إِلَى مَنِ ائْتَمَنَكَ وَلَا تَخُنْ مَنْ خَانَكَ", text: "Rends le dépôt à qui te l'a confié et ne trahis pas celui qui t'a trahi.", source: "Tirmidhi" },
      { arabic: "لَيْسَ الْمُؤْمِنُ بِالطَّعَّانِ وَلَا اللَّعَّانِ", text: "Le croyant n'est ni critiqueur, ni maudisseur.", source: "Tirmidhi" },
      { arabic: "مَنْ حَسُنَ إِسْلَامُ الْمَرْءِ تَرْكُهُ مَا لَا يَعْنِيهِ", text: "Fait partie du bel Islam de laisser ce qui ne nous regarde pas.", source: "Tirmidhi" },
