      { arabic: "تَبَسُّمُكَ فِي وَجْهِ أَخِيكَ لَكَ صَدَقَةٌ", text: "Ton sourire à ton frère est une aumône.", source: "Tirmidhi" },
      { arabic: "خَالِقِ النَّاسَ بِخُلُقٍ حَسَنٍ", text: "Comporte-toi avec les gens d'une belle manière.", source: "Tirmidhi" },
      { arabic: "إِنَّمَا الصَّبْرُ عِنْدَ الصَّدْمَةِ الْأُولَى", text: "La vraie patience est au moment du premier choc.", source: "Bukhari" },
      { arabic: "عَجَبًا لِأَمْرِ الْمُؤْمِنِ إِنَّ أَمْرَهُ كُلَّهُ خَيْرٌ", text: "Étonnante est l'affaire du croyant, tout est bien pour lui.", source: "Muslim" },
      { arabic: "إِنَّ الرِّفْقَ لَا يَكُونُ فِي شَيْءٍ إِلَّا زَانَهُ", text: "La douceur n'est dans une chose que pour l'embellir.", source: "Muslim" },
      { arabic: "حَرَّمَ اللَّهُ عَلَى النَّارِ كُلَّ هَيِّنٍ لَيِّنٍ سَهْلٍ", text: "Allah interdit au Feu toute personne douce, calme et facile à vivre.", source: "Ahmed" },
      { arabic: "أَحَبُّ النَّاسِ إِلَى اللَّهِ أَنْفَعُهُمْ لِلنَّاسِ", text: "Les gens les plus aimés d'Allah sont les plus utiles aux autres.", source: "Tabarani" },
      { arabic: "مَنْ سَتَرَ مُسْلِمًا سَتَرَهُ اللَّهُ فِي الدُّنْيَا وَالْآخِرَةِ", text: "Celui qui couvre un musulman, Allah le couvre ici-bas et dans l'au-delà.", source: "Muslim" },
      { arabic: "لَا تَحَاسَدُوا وَلَا تَبَاغَضُوا", text: "Ne vous enviez pas, ne vous haïssez pas.", source: "Muslim" },
      { arabic: "لَا يَحِلُّ لِمُسْلِمٍ أَنْ يَهْجُرَ أَخَاهُ فَوْقَ ثَلَاثٍ", text: "Il n'est pas permis au musulman d'ignorer son frère plus de trois jours.", source: "Bukhari" },
      { arabic: "تَهَادَوْا تَحَابُّوا", text: "Faites-vous des cadeaux, vous vous aimerez.", source: "Bukhari (Al-Adab)" },
      { arabic: "خَيْرُ الْأَصْحَابِ عِنْدَ اللَّهِ خَيْرُهُمْ لِصَاحِبِهِ", text: "Le meilleur compagnon auprès d'Allah est le meilleur pour son compagnon.", source: "Tirmidhi" },
      { arabic: "إِنَّ اللَّهَ يُحِبُّ إِذَا عَمِلَ أَحَدُكُمْ عَمَلًا أَنْ يُتْقِنَهُ", text: "Allah aime que lorsque l'un de vous fait un travail, il le perfectionne.", source: "Bayhaqi" },
      { arabic: "كُلُّ مَعْرُوفٍ صَدَقَةٌ", text: "Tout bienfait est une aumône.", source: "Bukhari" },
      { arabic: "امِيطُوا الْأَذَى عَنِ الطَّرِيقِ", text: "Enlevez la nuisance du chemin (c'est une aumône).", source: "Bukhari" },
      { arabic: "أَفْشُوا السَّلَامَ تَسْلَمُوا", text: "Répandez le salut (Salam), vous serez en paix.", source: "Ahmed" },
      { arabic: "الْحَيَاءُ لَا يَأْتِي إِلَّا بِخَيْرٍ", text: "La pudeur n'apporte que du bien.", source: "Bukhari" },
      { arabic: "لَا تَسُبُّوا الدِّيكَ فَإِنَّهُ يُوقِظُ لِلصَّلَاةِ", text: "N'insultez pas le coq, car il réveille pour la prière.", source: "Abu Dawud" },
      { arabic: "حُسْنُ الظَّنِّ مِنْ حُسْنِ الْعِبَادَةِ", text: "La bonne opinion fait partie de la bonne adoration.", source: "Abu Dawud" },
      { arabic: "لَا تَحْقِرَنَّ مِنَ الْمَعْرُوفِ شَيْئًا وَلَوْ أَنْ تَلْقَى أَخَاكَ بِوَجْهٍ طَلْقٍ", text: "Ne méprise aucune bonne action, même rencontrer ton frère avec un visage souriant.", source: "Muslim" }
