      { arabic: "وَهَلْ يَكُبُّ النَّاسَ فِي النَّارِ إِلَّا حَصَائِدُ أَلْسِنَتِهِمْ", text: "Qu'est-ce qui jette les gens en Enfer si ce n'est la récolte de leurs langues ?", source: "Tirmidhi" },
      { arabic: "أَثْقَلُ شَيْءٍ فِي الْمِيزَانِ حُسْنُ الْخُلُقِ", text: "La chose la plus lourde dans la balance est le bon caractère.", source: "Ahmed" },
      { arabic: "حُبُّ الدُّنْيَا رَأْسُ كُلِّ خَطِيئَةٍ", text: "L'amour de ce monde est la tête de toute faute.", source: "Bayhaqi" },
      { arabic: "إِذَا أَذْنَبَ الْعَبْدُ نُكِتَتْ فِي قَلْبِهِ نُكْتَةٌ سَوْدَاءُ", text: "Quand le serviteur commet un péché, un point noir s'inscrit sur son cœur.", source: "Tirmidhi" },
      { arabic: "الْمُجَاهِدُ مَنْ جَاهَدَ نَفْسَهُ", text: "Le vrai combattant est celui qui combat son âme (Ego).", source: "Tirmidhi" },
      { arabic: "الْكَيِّسُ مَنْ دَانَ نَفْسَهُ", text: "L'intelligent est celui qui demande des comptes à son âme.", source: "Tirmidhi" },
      { arabic: "إِنَّ الشَّيْطَانَ يَجْرِي مِنِ ابْنِ آدَمَ مَجْرَى الدَّمِ", text: "Le diable circule dans le fils d'Adam comme le sang.", source: "Bukhari" },
      { arabic: "اسْتَفْتِ قَلْبَكَ", text: "Consulte ton cœur (même si les gens te donnent des avis).", source: "Ahmed" },
