      { arabic: "إِذَا غَضِبَ أَحَدُكُمْ فَلْيَسْكُتْ", text: "Si l'un de vous est en colère, qu'il se taise.", source: "Ahmed" },
      { arabic: "ثَلَاثٌ مُهْلِكَاتٌ: شُحٌّ مُطَاعٌ وَهَوًى مُتَّبَعٌ وَإِعْجَابُ الْمَرْءِ بِنَفْسِهِ", text: "Trois choses périssent : l'avarice obéie, la passion suivie et l'auto-admiration.", source: "Tabarani" },
      { arabic: "لَا يَدْخُلُ الْجَنَّةَ مَنَّانٌ", text: "N'entre pas au Paradis celui qui rappelle ses bienfaits (Mannan).", source: "Nasa'i" },
      { arabic: "الرِّيَاءُ الشِّرْكُ الْأَصْغَرُ", text: "L'ostentation (Riya) est le petit polythéisme.", source: "Ahmed" },
      { arabic: "اللَّهُمَّ طَهِّرْ قَلْبِي مِنَ النِّفَاقِ", text: "Ô Allah purifie mon cœur de l'hypocrisie.", source: "Invocation" },
      { arabic: "إِنَّ الصِّدْقَ طُمَأْنِينَةٌ وَالْكَذِبَ رِيبَةٌ", text: "La vérité est apaisement, le mensonge est doute.", source: "Tirmidhi" },
      { arabic: "مَنْ تَرَكَ شَيْئًا لِلَّهِ عَوَّضَهُ اللَّهُ خَيْرًا مِنْهُ", text: "Celui qui délaisse une chose pour Allah, Allah la lui remplace par meilleure.", source: "Ahmed" },
      { arabic: "حُفَّتِ الْجَنَّةُ بِالْمَكَارِهِ وَحُفَّتِ النَّارُ بِالشَّهَوَاتِ", text: "Le Paradis est entouré de désagréments, l'Enfer est entouré de désirs.", source: "Muslim" },
      { arabic: "عَيْنَانِ لَا تَمَسُّهُمَا النَّارُ عَيْنٌ بَكَتْ مِنْ خَشْيَةِ اللَّهِ...", text: "Deux yeux ne seront pas touchés par le feu : un œil qui a pleuré par crainte d'Allah...", source: "Tirmidhi" },
      { arabic: "سَبْعَةٌ يُظِلُّهُمُ اللَّهُ... وَرَجُلٌ ذَكَرَ اللَّهَ خَالِيًا فَفَاضَتْ عَيْنَاهُ", text: "Sept seront sous l'ombre d'Allah... dont un homme qui évoqua Allah seul et ses yeux s'emplirent de larmes.", source: "Bukhari" },
      { arabic: "الْقُلُوبُ بَيْنَ إِصْبَعَيْنِ مِنْ أَصَابِعِ الرَّحْمَنِ", text: "Les cœurs sont entre deux doigts du Miséricordieux.", source: "Muslim" },
      { arabic: "لَا يُؤْمِنُ أَحَدُكُمْ حَتَّى يَكُونَ هَوَاهُ تَبَعًا لِمَا جِئْتُ بِهِ", text: "Nul ne croit vraiment tant que ses désirs ne suivent pas ce que j'ai apporté.", source: "Nawawi" },
      { arabic: "إِنَّ مِنَ الْيَقِينِ أَنْ لَا تُرْضِيَ النَّاسَ بِسَخَطِ اللَّهِ", text: "Fait partie de la certitude de ne pas satisfaire les gens par la colère d'Allah.", source: "Bayhaqi" },
      { arabic: "ازْهَدْ فِي الدُّنْيَا يُحِبَّكَ اللَّهُ", text: "Renonce à ce monde, Allah t'aimera.", source: "Ibn Majah" },
      { arabic: "أَزْهَدُ النَّاسِ فِي الْعَالِمِ أَهْلُهُ", text: "Les gens les plus indifférents au savant sont ses proches.", source: "Daylami" },
      { arabic: "إِنَّ اللَّهَ لَا يَمَلُّ حَتَّى تَمَلُّوا", text: "Allah ne se lasse pas (de récompenser) jusqu'à ce que vous vous lassiez (d'œuvrer).", source: "Bukhari" },
      { arabic: "اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ مُنْكَرَاتِ الْأَخْلَاقِ وَالْأَعْمَالِ", text: "Ô Allah je me réfugie auprès de Toi contre les mauvais caractères et les mauvaises actions.", source: "Tirmidhi" }
