      { arabic: "فَاطِمَةُ سَيِّدَةُ نِسَاءِ أَهْلِ الْجَنَّةِ", text: "Fatima est la maîtresse des femmes du Paradis.", source: "Bukhari" },
      { arabic: "عَلِيٌّ مِنِّي وَأَنَا مِنْ عَلِيٍّ", text: "Ali est de moi et je suis d'Ali.", source: "Tirmidhi" },
      { arabic: "أَنْتَ مِنِّي بِمَنْزِلَةِ هَارُونَ مِنْ مُوسَى", text: "Tu es pour moi ce que Aaron était pour Moïse.", source: "Bukhari & Muslim" },
      { arabic: "مَنْ كُنْتُ مَوْلَاهُ فَعَلِيٌّ مَوْلَاهُ", text: "Celui dont je suis le Maître, Ali est son Maître.", source: "Tirmidhi" },
      { arabic: "لَا يُحِبُّ عَلِيًّا إِلَّا مُؤْمِنٌ وَلَا يُبْغِضُهُ إِلَّا مُنَافِقٌ", text: "Nul n'aime Ali sauf un croyant, nul ne le déteste sauf un hypocrite.", source: "Muslim" },
      { arabic: "أَنَا مَدِينَةُ الْعِلْمِ وَعَلِيٌّ بَابُهَا", text: "Je suis la cité du savoir et Ali en est la porte.", source: "Tirmidhi (Hasan)" },
      { arabic: "الْحَسَنُ وَالْحُسَيْنُ سَيِّدَا شَبَابِ أَهْلِ الْجَنَّةِ", text: "Hasan et Husayn sont les maîtres des jeunes du Paradis.", source: "Tirmidhi" },
      { arabic: "حُسَيْنٌ مِنِّي وَأَنَا مِنْ حُسَيْنٍ", text: "Husayn est de moi et je suis de Husayn.", source: "Tirmidhi" },
      { arabic: "أَحَبَّ اللَّهُ مَنْ أَحَبَّ حُسَيْنًا", text: "Allah aime celui qui aime Husayn.", source: "Tirmidhi" },
      { arabic: "هُمَا رَيْحَانَتَايَ مِنَ الدُّنْيَا", text: "Ils (Hasan et Husayn) sont mes deux basilics de ce monde.", source: "Bukhari" },
      { arabic: "اللَّهُمَّ إِنِّي أُحِبُّهُمَا فَأَحِبَّهُمَا", text: "Ô Allah je les aime, alors aime-les.", source: "Bukhari" },
      { arabic: "الْمَهْدِيُّ مِنَّا أَهْلَ الْبَيْتِ", text: "Le Mahdi est de nous, les Ahl-ul-Bayt.", source: "Ibn Majah" },
      { arabic: "الْمَهْدِيُّ مِنْ وَلَدِ فَاطِمَةَ", text: "Le Mahdi est de la descendance de Fatima.", source: "Abu Dawud" },
      { arabic: "يُصْلِحُهُ اللَّهُ فِي لَيْلَةٍ", text: "Allah le (le Mahdi) rectifiera en une nuit.", source: "Ibn Majah" },
      { arabic: "إِنَّمَا يُرِيدُ اللَّهُ لِيُذْهِبَ عَنْكُمُ الرِّجْسَ أَهْلَ الْبَيْتِ", text: "Allah ne veut qu'éloigner de vous la souillure, ô Gens de la Maison.", source: "Coran (Ahzab)" },
      { arabic: "اللَّهُمَّ هَؤُلَاءِ أَهْلُ بَيْتِي", text: "Ô Allah, ceux-ci sont les gens de ma maison (sous le Manteau).", source: "Muslim" },
      { arabic: "مَثَلُ أَهْلِ بَيْتِي مَثَلُ سَفِينَةِ نُوحٍ", text: "L'exemple de ma famille est comme l'Arche de Noé.", source: "Tabarani" },
      { arabic: "النُّجُومُ أَمَانٌ لِأَهْلِ السَّمَاءِ وَأَهْلُ بَيْتِي أَمَانٌ لِأُمَّتِي", text: "Les étoiles sont une sécurité pour le ciel, et ma famille est une sécurité pour ma communauté.", source: "Mustadrak" },
      { arabic: "خَيْرُكُمْ خَيْرُكُمْ لِأَهْلِي", text: "Le meilleur d'entre vous est le meilleur pour ma famille.", source: "Tirmidhi" },
      { arabic: "أَرْبَعَةٌ أَنَا لَهُمْ شَفِيعٌ... وَالْمُكْرِمُ لِذُرِّيَّتِي", text: "Quatre personnes pour qui j'intercèderai... dont celui qui honore ma descendance.", source: "Kanz al-Ummal" },
      { arabic: "لَا تَقُومُ السَّاعَةُ حَتَّى يَمْلِكَ رَجُلٌ مِنْ أَهْلِ بَيْتِي", text: "L'Heure ne viendra pas avant qu'un homme de ma famille ne règne.", source: "Ahmed" },
      { arabic: "لِكُلِّ نَبِيٍّ عَصَبَةٌ... إِلَّا وَلَدَ فَاطِمَةَ فَأَنَا وَلِيُّهُمْ", text: "Tout prophète a une lignée... sauf les enfants de Fatima, je suis leur tuteur.", source: "Tabarani" },
      { arabic: "وَأَحِبُّوا أَهْلَ بَيْتِي لِحُبِّي", text: "Aimez ma famille par amour pour moi.", source: "Tirmidhi" },
      { arabic: "مَنْ آَذَى عَلِيًّا فَقَدْ آذَانِي", text: "Celui qui fait du mal à Ali m'a fait du mal.", source: "Ahmed" },
      { arabic: "اللَّهُمَّ وَالِ مَنْ وَالَاهُ وَعَادِ مَنْ عَادَاهُ", text: "Ô Allah, allie-Toi à celui qui s'allie à lui (Ali) et sois l'ennemi de son ennemi.", source: "Tirmidhi" },
      { arabic: "عَلِيٌّ مَعَ الْقُرْآنِ وَالْقُرْآنُ مَعَ عَلِيٍّ", text: "Ali est avec le Coran et le Coran est avec Ali.", source: "Tabarani" },
      { arabic: "السَّلَامُ عَلَى آلِ يَاسِينَ", text: "Paix sur la famille de Yasin (Muhammad).", source: "Coran / Tafsir" },
      { arabic: "لَا أَسْأَلُكُمْ عَلَيْهِ أَجْرًا إِلَّا الْمَوَدَّةَ فِي الْقُرْبَى", text: "Je ne vous demande pas de salaire si ce n'est l'affection pour les proches.", source: "Coran (Shura)" },
      { arabic: "نَحْنُ أَهْلُ بَيْتٍ لَا يُقَاسُ بِنَا أَحَدٌ", text: "Nous sommes les Ahl-ul-Bayt, personne ne peut nous être comparé.", source: "Daylami" },
      { arabic: "إِنَّ ابْنِي هَذَا سَيِّدٌ (الحسن)", text: "Mon fils que voici (Hasan) est un Sayyid (maître).", source: "Bukhari" },
      { arabic: "وَلَعَلَّ اللَّهَ أَنْ يُصْلِحَ بِهِ بَيْنَ فِئَتَيْنِ مِنَ الْمُسْلِمِينَ", text: "Peut-être qu'Allah réconciliera par lui deux groupes de musulmans.", source: "Bukhari" },
      { arabic: "أَوَّلُ مَنْ يَدْخُلُ عَلَيَّ الْجَنَّةَ فَاطِمَةُ", text: "La première à entrer au Paradis après moi est Fatima.", source: "Hakim" },
      { arabic: "يَا فَاطِمَةُ أَلَا تَرْضَيْنَ أَنْ تَكُونِي سَيِّدَةَ نِسَاءِ الْمُؤْمِنِينَ", text: "Ô Fatima, n'es-tu pas satisfaite d'être la maîtresse des croyantes ?", source: "Bukhari" },
      { arabic: "إِنَّمَا سُمِّيَتْ فَاطِمَةَ لِأَنَّ اللَّهَ فَطَمَهَا وَمُحِبِّيهَا عَنِ النَّارِ", text: "Elle a été nommée Fatima car Allah l'a sevrée (protégée) elle et ceux qui l'aiment du Feu.", source: "Daylami" },
      { arabic: "الشَّقَاوَةُ كُلُّ الشَّقَاوَةِ لِمَنْ أَبْغَضَنَا", text: "Le malheur total est pour celui qui nous déteste.", source: "Tabarani" },
      { arabic: "مَنْ مَاتَ عَلَى حُبِّ آلِ مُحَمَّدٍ مَاتَ شَهِيدًا", text: "Celui qui meurt avec l'amour de la famille de Muhammad meurt martyr.", source: "Tafsir Kashshaf" },
      { arabic: "لِكُلِّ شَيْءٍ أَسَاسٌ وَأَسَاسُ الْإِسْلَامِ حُبُّنَا أَهْلَ الْبَيْتِ", text: "Toute chose a une base, et la base de l'Islam est notre amour.", source: "Kanz" },
      { arabic: "الصَّلَاةُ عَلَيْنَا تَمْحَقُ الذُّنُوبَ", text: "La prière sur nous efface les péchés comme l'eau éteint le feu.", source: "Daylami" },
      { arabic: "لَا يَزُولُ قَدَمَا عَبْدٍ... حَتَّى يُسْأَلَ عَنْ حُبِّنَا أَهْلَ الْبَيْتِ", text: "Les pieds du serviteur ne bougeront pas... avant d'être interrogé sur notre amour.", source: "Tabarani" },
      { arabic: "لَا يُحِبُّنَا إِلَّا مُؤْمِنٌ تَقِيٌّ وَلَا يُبْغِضُنَا إِلَّا مُنَافِقٌ شَقِيٌّ", text: "Seul un croyant pieux nous aime et seul un hypocrite malheureux nous déteste.", source: "Kanz" },
      { arabic: "إِنَّ حُبَّنَا أَهْلَ الْبَيْتِ لَيُسَاقِطُ الذُّنُوبَ", text: "L'amour pour nous, Ahl-ul-Bayt, fait tomber les péchés.", source: "Tabarani" }
    ]
  },
  {
    id: 'mort_audela',
    title: "Mort & Au-delà",
    icon: Sun,
    description: "La mort, le Paradis, l'Enfer et la fin des temps",
    hadiths: [
      { arabic: "أَكْثِرُوا ذِكْرَ هَاذِمِ اللَّذَّاتِ", text: "Multipliez le rappel de celle qui brise les plaisirs (la mort).", source: "Tirmidhi" },
      { arabic: "الْقَبْرُ أَوَّلُ مَنَازِلِ الْآخِرَةِ", text: "La tombe est la première demeure de l'Au-delà.", source: "Tirmidhi" },
      { arabic: "الدُّنْيَا سِجْنُ الْمُؤْمِنِ وَجَنَّةُ الْكَافِرِ", text: "Ce monde est la prison du croyant et le paradis du mécréant.", source: "Muslim" },
      { arabic: "كُنْ فِي الدُّنْيَا كَأَنَّكَ غَرِيبٌ", text: "Sois dans ce monde comme un étranger.", source: "Bukhari" },
      { arabic: "يَتْبَعُ الْمَيِّتَ ثَلَاثَةٌ... فَيَرْجِعُ اثْنَانِ وَيَبْقَى وَاحِدٌ", text: "Trois suivent le mort... deux reviennent, un reste : ses œuvres.", source: "Bukhari" },
      { arabic: "مَنْ أَحَبَّ لِقَاءَ اللَّهِ أَحَبَّ اللَّهُ لِقَاءَهُ", text: "Celui qui aime rencontrer Allah, Allah aime le rencontrer.", source: "Bukhari" },
      { arabic: "إِذَا مَاتَ الْإِنْسَانُ انْقَطَعَ عَنْهُ عَمَلُهُ إِلَّا مِنْ ثَلَاثَةٍ", text: "Quand l'homme meurt, ses œuvres cessent sauf trois...", source: "Muslim" },
      { arabic: "يَقُولُ ابْنُ آدَمَ مَالِي مَالِي", text: "Le fils d'Adam dit 'Mon argent, mon argent', mais n'as-tu que ce que tu as mangé...", source: "Muslim" },
      { arabic: "لَوْ كَانَتِ الدُّنْيَا تَعْدِلُ عِنْدَ اللَّهِ جَنَاحَ بَعُوضَةٍ", text: "Si ce monde valait chez Allah l'aile d'un moustique...", source: "Tirmidhi" },
      { arabic: "مَوْضِعُ سَوْطٍ فِي الْجَنَّةِ خَيْرٌ مِنَ الدُّنْيَا", text: "La place d'un fouet au Paradis vaut mieux que le monde entier.", source: "Bukhari" },
      { arabic: "فِيهَا مَا لَا عَيْنٌ رَأَتْ", text: "Il y a (au Paradis) ce qu'aucun œil n'a vu.", source: "Bukhari" },
      { arabic: "إِنَّ أَهْلَ الْجَنَّةِ يَتَرَاءَوْنَ أَهْلَ الْغُرَفِ", text: "Les gens du Paradis verront ceux des étages supérieurs comme des étoiles.", source: "Bukhari" },
      { arabic: "أَوَّلُ زُمْرَةٍ تَدْخُلُ الْجَنَّةَ عَلَى صُورَةِ الْقَمَرِ", text: "Le premier groupe entrant au Paradis aura l'éclat de la lune.", source: "Bukhari" },
      { arabic: "إِنَّ فِي الْجَنَّةِ لَسُوقًا يَأْتُونَهَا كُلَّ جُمُعَةٍ", text: "Il y a au Paradis un marché où ils vont chaque vendredi.", source: "Muslim" },
      { arabic: "يُقَالُ لِصَاحِبِ الْقُرْآنِ اقْرَأْ وَارْتَقِ", text: "On dira au lecteur du Coran : Lis et monte...", source: "Abu Dawud" },
      { arabic: "نَارُكُمْ هَذِهِ جُزْءٌ مِنْ سَبْعِينَ جُزْءًا مِنْ نَارِ جَهَنَّمَ", text: "Votre feu que vous allumez est une partie des 70 parties du feu de l'Enfer.", source: "Bukhari" },
      { arabic: "أَهْوَنُ أَهْلِ النَّارِ عَذَابًا...", text: "Le moins châtié de l'Enfer aura des braises sous les pieds...", source: "Muslim" },
      { arabic: "يُؤْتَى بِالْمَوْتِ كَهَيْئَةِ كَبْشٍ أَمْلَحَ فَيُذْبَحُ", text: "La mort sera amenée sous forme de bélier et égorgée (plus de mort).", source: "Bukhari" },
      { arabic: "لَا تَقُومُ السَّاعَةُ حَتَّى تَطْلُعَ الشَّمْسُ مِنْ مَغْرِبِهَا", text: "L'Heure ne viendra pas tant que le soleil ne se lèvera pas de l'ouest.", source: "Bukhari" },
      { arabic: "يَخْرُجُ الدَّجَّالُ فِي أُمَّتِي", text: "Le Dajjal sortira dans ma communauté.", source: "Muslim" },
      { arabic: "كَيْفَ أَنْتُمْ إِذَا نَزَلَ ابْنُ مَرْيَمَ فِيكُمْ", text: "Comment serez-vous quand le fils de Marie descendra parmi vous ?", source: "Bukhari" },
      { arabic: "لَا تَزَالُ طَائِفَةٌ مِنْ أُمَّتِي ظَاهِرِينَ عَلَى الْحَقِّ", text: "Un groupe de ma communauté restera sur la vérité jusqu'à l'Ordre d'Allah.", source: "Muslim" },
      { arabic: "بَدَأَ الْإِسْلَامُ غَرِيبًا وَسَيَعُودُ غَرِيبًا", text: "L'Islam a commencé étranger et redeviendra étranger.", source: "Muslim" },
      { arabic: "يَقْبِضُ اللَّهُ الْأَرْضَ وَيَطْوِي السَّمَوَاتِ بِيَمِينِهِ", text: "Allah saisira la terre et pliera les cieux de Sa main droite.", source: "Bukhari" },
      { arabic: "يُحْشَرُ النَّاسُ يَوْمَ الْقِيَامَةِ حُفَاةً عُرَاةً", text: "Les gens seront rassemblés pieds nus, nus et incirconcis.", source: "Bukhari" },
      { arabic: "إِنِّي فَرَطُكُمْ عَلَى الْحَوْضِ", text: "Je vous précéderai au Bassin (Kawthar).", source: "Bukhari" },
      { arabic: "شَفَاعَتِي لِأَهْلِ الْكَبَائِرِ مِنْ أُمَّتِي", text: "Mon intercession est pour ceux qui ont commis des grands péchés dans ma communauté.", source: "Tirmidhi" },
      { arabic: "يَخْرُجُ مِنَ النَّارِ مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ", text: "Sortira du Feu quiconque a dit La ilaha illa Allah.", source: "Bukhari" },
      { arabic: "سَبْعَةٌ يُظِلُّهُمُ اللَّهُ فِي ظِلِّهِ", text: "Sept personnes qu'Allah ombragera le jour où il n'y aura d'ombre que la Sienne.", source: "Bukhari" },
      { arabic: "الْمَرْءُ مَعَ مَنْ أَحَبَّ", text: "L'homme sera avec celui qu'il a aimé.", source: "Bukhari" },
      { arabic: "لَنْ يُدْخِلَ أَحَدًا عَمَلُهُ الْجَنَّةَ... وَلَا أَنَا إِلَّا أَنْ يَتَغَمَّدَنِي اللَّهُ بِفَضْلٍ", text: "Personne n'entrera au Paradis par ses actes... même pas moi, sauf si Allah me couvre de Sa grâce.", source: "Bukhari" },
      { arabic: "إِنَّ أَدْنَى مَقْعَدِ أَحَدِكُمْ مِنَ الْجَنَّةِ...", text: "La plus petite place de l'un de vous au Paradis est...", source: "Muslim" },
      { arabic: "إِنَّ لِلَّهِ مِائَةَ رَحْمَةٍ أَنْزَلَ مِنْهَا رَحْمَةً وَاحِدَةً", text: "Allah a cent miséricordes, Il en a descendu une seule sur terre.", source: "Muslim" },
      { arabic: "يُدْنَى الْمُؤْمِنُ مِنْ رَبِّهِ حَتَّى يَضَعَ عَلَيْهِ كَنَفَهُ", text: "Le croyant sera approché de son Seigneur jusqu'à ce qu'Il le couvre de Son voile.", source: "Bukhari" },
      { arabic: "مَا مِنْكُمْ مِنْ أَحَدٍ إِلَّا سَيُكَلِّمُهُ رَبُّهُ", text: "Il n'y a personne parmi vous à qui son Seigneur ne parlera pas.", source: "Bukhari" },
      { arabic: "وُجُوهٌ يَوْمَئِذٍ نَاضِرَةٌ إِلَى رَبِّهَا نَاظِرَةٌ", text: "Ce jour-là, il y aura des visages resplendissants qui regarderont leur Seigneur.", source: "Coran / Bukhari" },
      { arabic: "أَعِدُّوا لِلْمَوْتِ عُدَّتَهُ", text: "Préparez pour la mort ses provisions.", source: "Baihaqi" },
      { arabic: "الْكَيِّسُ مَنْ دَانَ نَفْسَهُ وَعَمِلَ لِمَا بَعْدَ الْمَوْتِ", text: "L'intelligent est celui qui se juge et œuvre pour après la mort.", source: "Tirmidhi" },
      { arabic: "لَا يَتَمَنَّيَنَّ أَحَدُكُمُ الْمَوْتَ لِضُرٍّ نَزَلَ بِهِ", text: "Que personne ne souhaite la mort à cause d'un mal qui l'a touché.", source: "Bukhari" },
      { arabic: "إِنَّ رُوحَ الْمُؤْمِنِ طَائِرٌ يَعْلُقُ فِي شَجَرِ الْجَنَّةِ", text: "L'âme du croyant est un oiseau perché dans les arbres du Paradis.", source: "Nasa'i" },
      { arabic: "كُلُّ نَفْسٍ ذَائِقَةُ الْمَوْتِ", text: "Toute âme goûtera la mort.", source: "Coran" },
