        <main className={`min-h-screen relative z-10 ${activeTab === 'landing' ? 'bg-white dark:bg-slate-950' : ''}`}>
          <div className={`${activeTab === 'landing' ? '' : 'p-6'} min-h-screen`}>
             {renderContent()}
