const App: React.FC = () => {
  // Check if user has visited before to determine starting page (Website feel)
  const [activeTab, setActiveTab] = useState(() => {
    const hasVisited = localStorage.getItem('has_visited');
    const isStandalone = window.matchMedia('(display-mode: standalone)').matches || (window.navigator as any).standalone;
    // If it's an installed app (standalone), go to home. 
    // If it's a website visitor and first time, go to landing.
    return (hasVisited || isStandalone) ? 'home' : 'landing';
  });

  const [location, setLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [prayerData, setPrayerData] = useState<{ timings: PrayerTimes, date: HijriDate } | null>(null);
  const [loadingPrayers, setLoadingPrayers] = useState(true);
  const [showSettings, setShowSettings] = useState(false);
  const [language, setLanguage] = useState(() => localStorage.getItem('language') || 'en');
  const [calculationMethod, setCalculationMethod] = useState(() => parseInt(localStorage.getItem('calc_method') || '2'));
  const [darkMode, setDarkMode] = useState(() => {
    const saved = localStorage.getItem('darkMode');
    return saved === null ? window.matchMedia('(prefers-color-scheme: dark)').matches : saved === 'true';
  });

  // PWA State
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
  const [isIOS, setIsIOS] = useState(false);
  const [isStandalone, setIsStandalone] = useState(false);
  const [showIOSPrompt, setShowIOSPrompt] = useState(false);

  const t = TRANSLATIONS[language as keyof typeof TRANSLATIONS] || TRANSLATIONS.en;

  // Handle Dark Mode
  useEffect(() => {
    if (darkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
    localStorage.setItem('darkMode', darkMode.toString());
  }, [darkMode]);

  // Handle Language & RTL
  useEffect(() => {
    localStorage.setItem('language', language);
    if (language === 'ar') {
      document.documentElement.dir = 'rtl';
      document.body.classList.add('font-arabic');
    } else {
      document.documentElement.dir = 'ltr';
      document.body.classList.remove('font-arabic');
    }
  }, [language]);

  // PWA Installation Logic
  useEffect(() => {
    // Check if running in standalone mode (already installed)
    const isStand = window.matchMedia('(display-mode: standalone)').matches || (window.navigator as any).standalone;
    setIsStandalone(isStand);

    // Detect iOS
    const ios = /iPad|iPhone|iPod/.test(navigator.userAgent) && !(window as any).MSStream;
    setIsIOS(ios);

    // Capture install prompt for Android/Desktop
    const handleBeforeInstallPrompt = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };

    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

    return () => {
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    };
  }, []);

  const handleInstallClick = () => {
    if (deferredPrompt) {
      deferredPrompt.prompt();
      deferredPrompt.userChoice.then((choiceResult: any) => {
        if (choiceResult.outcome === 'accepted') {
          setDeferredPrompt(null);
        }
      });
    } else if (isIOS) {
      setShowIOSPrompt(true);
    }
  };

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (p) => setLocation({ lat: p.coords.latitude, lng: p.coords.longitude }),
        () => setLocation({ lat: 51.5074, lng: -0.1278 })
      );
    }
  }, []);

  useEffect(() => {
    const fetch = async () => {
      if (!location) return;
      setLoadingPrayers(true);
      const data = await getPrayerTimes(location.lat, location.lng, calculationMethod);
      setPrayerData(data);
      setLoadingPrayers(false);
    };
    fetch();
  }, [location, calculationMethod]);

  const renderContent = () => {
    switch (activeTab) {
      case 'home':
        return (
          <div className="space-y-8 pb-32 animate-fade-in">
